import React, { useState, useRef, useEffect } from "react";
import { useNavigate } from "react-router-dom";
import { motion, AnimatePresence } from "framer-motion";
import { Mail, HelpCircle, ChevronDown, ArrowLeft, Send } from "lucide-react";

function Support() {
  const navigate = useNavigate();
  const [expandedFAQ, setExpandedFAQ] = useState(null);
  const [email, setEmail] = useState("");
  const [message, setMessage] = useState("");
  const [isSending, setIsSending] = useState(false);
  const containerRef = useRef(null);

  const supportEmail = "kparkjun@gmail.com";
  const appName = "DVDHolic";

  const faqItems = [
    {
      id: "1",
      question: "회원 탈퇴는 어떻게 하나요?",
      answer: "로그인 후 대시보드에서 '계정' 버튼을 클릭하면 계정 설정 페이지로 이동합니다. 해당 페이지에서 '탈퇴'를 입력하고 계정 삭제 버튼을 누르시면 됩니다."
    },
    {
      id: "2",
      question: "앱 이용 중 오류가 발생하면 어떻게 하나요?",
      answer: "오류 발생 시 아래 이메일로 상황을 알려 주시면 빠르게 확인하여 답변드리겠습니다. 오류 화면 캡처와 함께 보내주시면 더 빠른 해결이 가능합니다."
    },
    {
      id: "3",
      question: "개인정보는 어떻게 처리되나요?",
      answer: "DVDHolic은 사용자의 개인정보를 안전하게 보호합니다. 개인정보 처리에 관한 자세한 문의는 위 이메일로 보내 주세요."
    },
    {
      id: "4",
      question: "좋아요/싫어요는 어떻게 작동하나요?",
      answer: "로그인 후 영화 상세 정보에서 좋아요/싫어요 버튼을 누르면 해당 영화에 대한 평가가 저장됩니다. 좋아요를 누른 영화들은 '내 찜 목록'에서 확인할 수 있습니다."
    },
    {
      id: "5",
      question: "맞춤 추천은 어떻게 받을 수 있나요?",
      answer: "좋아요를 누른 영화들의 장르를 분석하여 비슷한 장르의 영화를 추천해 드립니다. 더 많은 영화에 좋아요를 누를수록 더 정확한 추천을 받으실 수 있습니다."
    }
  ];

  const toggleFAQ = (id) => {
    setExpandedFAQ(expandedFAQ === id ? null : id);
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    if (!email || !message) return;
    
    setIsSending(true);
    setTimeout(() => {
      window.location.href = `mailto:${supportEmail}?subject=DVDHolic 문의&body=${encodeURIComponent(message)}%0A%0A보낸사람: ${email}`;
      setIsSending(false);
      setEmail("");
      setMessage("");
    }, 500);
  };

  // Animated Gradient Background
  useEffect(() => {
    let animationFrame;
    let width = 125;
    let directionWidth = 1;
    const breathingRange = 5;
    const animationSpeed = 0.02;
    
    const gradientColors = [
      "#0A0A0A",
      "#6366F1",
      "#8B5CF6",
      "#A855F7",
      "#C084FC",
      "#E879F9",
      "#F0ABFC"
    ];
    const gradientStops = [35, 50, 60, 70, 80, 90, 100];

    const animateGradient = () => {
      if (width >= 125 + breathingRange) directionWidth = -1;
      if (width <= 125 - breathingRange) directionWidth = 1;
      width += directionWidth * animationSpeed;

      const gradientStopsString = gradientStops
        .map((stop, index) => `${gradientColors[index]} ${stop}%`)
        .join(", ");

      const gradient = `radial-gradient(${width}% ${width}% at 50% 20%, ${gradientStopsString})`;

      if (containerRef.current) {
        containerRef.current.style.background = gradient;
      }

      animationFrame = requestAnimationFrame(animateGradient);
    };

    animationFrame = requestAnimationFrame(animateGradient);
    return () => cancelAnimationFrame(animationFrame);
  }, []);

  const fadeInUp = {
    hidden: { opacity: 0, y: 60 },
    visible: {
      opacity: 1,
      y: 0,
      transition: {
        duration: 0.8,
        ease: [0.23, 0.86, 0.39, 0.96]
      }
    }
  };

  const staggerContainer = {
    hidden: { opacity: 0 },
    visible: {
      opacity: 1,
      transition: {
        staggerChildren: 0.2,
        delayChildren: 0.3
      }
    }
  };

  return (
    <div style={{ position: "relative", minHeight: "100vh", overflow: "hidden" }}>
      {/* Animated Background */}
      <motion.div
        initial={{ opacity: 0, scale: 1.5 }}
        animate={{ opacity: 1, scale: 1, transition: { duration: 2, ease: [0.25, 0.1, 0.25, 1] } }}
        style={{ position: "absolute", inset: 0, overflow: "hidden" }}
      >
        <div ref={containerRef} style={{ position: "absolute", inset: 0 }} />
      </motion.div>

      {/* Floating particles */}
      {[...Array(15)].map((_, i) => (
        <motion.div
          key={i}
          style={{
            position: "absolute",
            width: "4px",
            height: "4px",
            background: "rgba(255, 255, 255, 0.2)",
            borderRadius: "50%",
            left: `${Math.random() * 100}%`,
            top: `${Math.random() * 100}%`,
          }}
          animate={{
            y: [0, -100, 0],
            opacity: [0.2, 1, 0.2],
            scale: [1, 2, 1],
          }}
          transition={{
            duration: 4 + Math.random() * 4,
            repeat: Infinity,
            ease: "easeInOut",
            delay: Math.random() * 2,
          }}
        />
      ))}

      {/* Main Content */}
      <motion.div
        style={{
          position: "relative",
          zIndex: 10,
          maxWidth: "900px",
          margin: "0 auto",
          padding: "40px 20px",
        }}
        variants={staggerContainer}
        initial="hidden"
        animate="visible"
      >
        {/* Back Button */}
        <motion.button
          initial={{ opacity: 0, x: -20 }}
          animate={{ opacity: 1, x: 0 }}
          transition={{ duration: 0.5 }}
          onClick={() => navigate(-1)}
          style={{
            display: "flex",
            alignItems: "center",
            gap: "8px",
            padding: "10px 16px",
            background: "rgba(255, 255, 255, 0.08)",
            backdropFilter: "blur(10px)",
            border: "1px solid rgba(255, 255, 255, 0.15)",
            borderRadius: "12px",
            color: "#fff",
            fontSize: "14px",
            fontWeight: 600,
            cursor: "pointer",
            marginBottom: "32px",
            transition: "all 0.2s ease",
          }}
          onMouseEnter={(e) => {
            e.currentTarget.style.background = "rgba(255, 255, 255, 0.12)";
            e.currentTarget.style.transform = "scale(1.02)";
          }}
          onMouseLeave={(e) => {
            e.currentTarget.style.background = "rgba(255, 255, 255, 0.08)";
            e.currentTarget.style.transform = "scale(1)";
          }}
        >
          <ArrowLeft size={18} />
          뒤로 가기
        </motion.button>

        {/* Header */}
        <motion.div
          variants={fadeInUp}
          style={{ textAlign: "center", marginBottom: "48px" }}
        >
          <motion.div
            style={{
              display: "inline-flex",
              alignItems: "center",
              gap: "12px",
              padding: "8px 20px",
              background: "rgba(255, 255, 255, 0.08)",
              border: "1px solid rgba(255, 255, 255, 0.15)",
              borderRadius: "999px",
              marginBottom: "24px",
            }}
            whileHover={{ scale: 1.05 }}
          >
            <HelpCircle size={16} color="rgba(165, 180, 252, 1)" />
            <span style={{ fontSize: "14px", fontWeight: 500, color: "rgba(255, 255, 255, 0.8)" }}>
              Premium Support
            </span>
          </motion.div>

          <h1
            style={{
              fontSize: "clamp(36px, 7vw, 64px)",
              fontWeight: 800,
              marginBottom: "16px",
              lineHeight: 1.1,
            }}
          >
            <span style={{ color: "#fff" }}>도움이 필요하신가요?</span>
            <br />
            <motion.span
              style={{
                background: "linear-gradient(135deg, #a5b4fc, #c084fc, #f472b6)",
                WebkitBackgroundClip: "text",
                WebkitTextFillColor: "transparent",
                backgroundClip: "text",
                backgroundSize: "200% 200%",
              }}
              animate={{
                backgroundPosition: ['0% 50%', '100% 50%', '0% 50%'],
              }}
              transition={{
                duration: 5,
                repeat: Infinity,
                ease: "easeInOut"
              }}
            >
              언제든 연락주세요
            </motion.span>
          </h1>

          <p style={{ color: "rgba(255, 255, 255, 0.6)", fontSize: "18px", maxWidth: "600px", margin: "0 auto" }}>
            {appName} 앱 사용에 관한 문의나 지원이 필요하시면 아래 양식을 이용해 주세요.
          </p>
        </motion.div>

        {/* Contact Form Card */}
        <motion.div
          variants={fadeInUp}
          style={{
            backdropFilter: "blur(20px)",
            background: "rgba(255, 255, 255, 0.1)",
            border: "1px solid rgba(255, 255, 255, 0.2)",
            borderRadius: "24px",
            overflow: "hidden",
            marginBottom: "32px",
          }}
        >
          {/* Card Header */}
          <div style={{ padding: "24px 32px", borderBottom: "1px solid rgba(255, 255, 255, 0.1)" }}>
            <div style={{ display: "flex", alignItems: "center", gap: "16px" }}>
              <div
                style={{
                  width: "48px",
                  height: "48px",
                  borderRadius: "14px",
                  background: "linear-gradient(135deg, rgba(99, 102, 241, 0.2), rgba(168, 85, 247, 0.2))",
                  border: "1px solid rgba(255, 255, 255, 0.2)",
                  display: "flex",
                  alignItems: "center",
                  justifyContent: "center",
                }}
              >
                <Mail size={24} color="rgba(165, 180, 252, 1)" />
              </div>
              <div>
                <h2 style={{ color: "#fff", fontSize: "22px", fontWeight: 700, marginBottom: "4px" }}>
                  문의하기
                </h2>
                <p style={{ color: "rgba(255, 255, 255, 0.7)", fontSize: "14px" }}>
                  메시지를 보내주시면 빠르게 답변드리겠습니다
                </p>
              </div>
            </div>
          </div>

          {/* Card Content - Form */}
          <form onSubmit={handleSubmit} style={{ padding: "24px 32px" }}>
            <div style={{ marginBottom: "20px" }}>
              <label
                htmlFor="email"
                style={{
                  display: "block",
                  fontSize: "14px",
                  fontWeight: 500,
                  color: "rgba(255, 255, 255, 0.8)",
                  marginBottom: "8px",
                }}
              >
                이메일 주소
              </label>
              <input
                id="email"
                type="email"
                value={email}
                onChange={(e) => setEmail(e.target.value)}
                placeholder="your@email.com"
                required
                style={{
                  width: "100%",
                  padding: "14px 18px",
                  borderRadius: "12px",
                  background: "rgba(255, 255, 255, 0.05)",
                  border: "1px solid rgba(255, 255, 255, 0.1)",
                  color: "#fff",
                  fontSize: "15px",
                  outline: "none",
                  transition: "all 0.2s ease",
                  boxSizing: "border-box",
                }}
                onFocus={(e) => {
                  e.target.style.borderColor = "rgba(99, 102, 241, 0.5)";
                  e.target.style.boxShadow = "0 0 0 3px rgba(99, 102, 241, 0.2)";
                }}
                onBlur={(e) => {
                  e.target.style.borderColor = "rgba(255, 255, 255, 0.1)";
                  e.target.style.boxShadow = "none";
                }}
              />
            </div>

            <div style={{ marginBottom: "24px" }}>
              <label
                htmlFor="message"
                style={{
                  display: "block",
                  fontSize: "14px",
                  fontWeight: 500,
                  color: "rgba(255, 255, 255, 0.8)",
                  marginBottom: "8px",
                }}
              >
                문의 내용
              </label>
              <textarea
                id="message"
                value={message}
                onChange={(e) => setMessage(e.target.value)}
                placeholder="어떤 도움이 필요하신가요?"
                required
                rows={4}
                style={{
                  width: "100%",
                  padding: "14px 18px",
                  borderRadius: "12px",
                  background: "rgba(255, 255, 255, 0.05)",
                  border: "1px solid rgba(255, 255, 255, 0.1)",
                  color: "#fff",
                  fontSize: "15px",
                  outline: "none",
                  transition: "all 0.2s ease",
                  resize: "none",
                  boxSizing: "border-box",
                }}
                onFocus={(e) => {
                  e.target.style.borderColor = "rgba(99, 102, 241, 0.5)";
                  e.target.style.boxShadow = "0 0 0 3px rgba(99, 102, 241, 0.2)";
                }}
                onBlur={(e) => {
                  e.target.style.borderColor = "rgba(255, 255, 255, 0.1)";
                  e.target.style.boxShadow = "none";
                }}
              />
            </div>

            <motion.button
              type="submit"
              disabled={isSending}
              whileHover={{ scale: 1.02 }}
              whileTap={{ scale: 0.98 }}
              style={{
                width: "100%",
                padding: "16px",
                background: "linear-gradient(135deg, #6366f1, #8b5cf6)",
                border: "none",
                borderRadius: "14px",
                color: "#fff",
                fontSize: "16px",
                fontWeight: 600,
                cursor: isSending ? "wait" : "pointer",
                display: "flex",
                alignItems: "center",
                justifyContent: "center",
                gap: "8px",
                transition: "all 0.2s ease",
                boxShadow: "0 4px 15px rgba(99, 102, 241, 0.3)",
              }}
            >
              <Send size={18} />
              {isSending ? "전송 중..." : "메시지 보내기"}
            </motion.button>
          </form>

          {/* Direct Email Link */}
          <div
            style={{
              padding: "20px 32px",
              borderTop: "1px solid rgba(255, 255, 255, 0.1)",
              textAlign: "center",
            }}
          >
            <p style={{ color: "rgba(255, 255, 255, 0.6)", fontSize: "14px" }}>
              또는 직접 이메일을 보내주세요:{" "}
              <a
                href={`mailto:${supportEmail}`}
                style={{
                  color: "rgba(165, 180, 252, 1)",
                  textDecoration: "none",
                  fontWeight: 600,
                  transition: "color 0.2s ease",
                }}
                onMouseEnter={(e) => e.target.style.color = "rgba(192, 132, 252, 1)"}
                onMouseLeave={(e) => e.target.style.color = "rgba(165, 180, 252, 1)"}
              >
                {supportEmail}
              </a>
            </p>
          </div>
        </motion.div>

        {/* FAQ Section */}
        <motion.div variants={fadeInUp}>
          <div style={{ textAlign: "center", marginBottom: "32px" }}>
            <h2 style={{ color: "#fff", fontSize: "32px", fontWeight: 700, marginBottom: "8px" }}>
              자주 묻는 질문
            </h2>
            <p style={{ color: "rgba(255, 255, 255, 0.6)", fontSize: "16px" }}>
              {appName} 이용에 관한 일반적인 질문들
            </p>
          </div>

          <div style={{ display: "flex", flexDirection: "column", gap: "12px" }}>
            {faqItems.map((item, index) => (
              <motion.div
                key={item.id}
                initial={{ opacity: 0, y: 20 }}
                animate={{ opacity: 1, y: 0 }}
                transition={{ delay: index * 0.1 }}
                style={{
                  backdropFilter: "blur(20px)",
                  background: "rgba(255, 255, 255, 0.1)",
                  border: "1px solid rgba(255, 255, 255, 0.2)",
                  borderRadius: "16px",
                  overflow: "hidden",
                }}
              >
                <button
                  onClick={() => toggleFAQ(item.id)}
                  style={{
                    width: "100%",
                    padding: "20px 24px",
                    display: "flex",
                    alignItems: "center",
                    justifyContent: "space-between",
                    background: "transparent",
                    border: "none",
                    cursor: "pointer",
                    textAlign: "left",
                    transition: "background 0.2s ease",
                  }}
                  onMouseEnter={(e) => {
                    e.currentTarget.style.background = "rgba(255, 255, 255, 0.05)";
                  }}
                  onMouseLeave={(e) => {
                    e.currentTarget.style.background = "transparent";
                  }}
                >
                  <span style={{ color: "#fff", fontSize: "16px", fontWeight: 500, paddingRight: "16px" }}>
                    {item.question}
                  </span>
                  <motion.div
                    animate={{ rotate: expandedFAQ === item.id ? 180 : 0 }}
                    transition={{ duration: 0.3 }}
                    style={{ flexShrink: 0 }}
                  >
                    <ChevronDown size={20} color="rgba(255, 255, 255, 0.6)" />
                  </motion.div>
                </button>

                <AnimatePresence>
                  {expandedFAQ === item.id && (
                    <motion.div
                      initial={{ height: 0, opacity: 0 }}
                      animate={{
                        height: "auto",
                        opacity: 1,
                        transition: {
                          height: { duration: 0.3 },
                          opacity: { duration: 0.25, delay: 0.1 },
                        },
                      }}
                      exit={{
                        height: 0,
                        opacity: 0,
                        transition: {
                          height: { duration: 0.25 },
                          opacity: { duration: 0.15 },
                        },
                      }}
                      style={{ overflow: "hidden" }}
                    >
                      <div
                        style={{
                          padding: "0 24px 20px 24px",
                          color: "rgba(255, 255, 255, 0.7)",
                          fontSize: "15px",
                          lineHeight: 1.6,
                          borderTop: "1px solid rgba(255, 255, 255, 0.1)",
                          paddingTop: "16px",
                        }}
                      >
                        {item.answer}
                      </div>
                    </motion.div>
                  )}
                </AnimatePresence>
              </motion.div>
            ))}
          </div>
        </motion.div>
      </motion.div>
    </div>
  );
}

export default Support;
