import React, { useState } from "react";
import { useNavigate } from "react-router-dom";
import axios from "../axiosConfig";
import { motion } from "framer-motion";
import { AlertTriangle, Trash2, ArrowLeft, User } from "lucide-react";

function Account() {
  const [confirmText, setConfirmText] = useState("");
  const [isDeleting, setIsDeleting] = useState(false);
  const navigate = useNavigate();

  const CONFIRM_PHRASE = "탈퇴";

  const handleDeleteAccount = async () => {
    if (confirmText !== CONFIRM_PHRASE) {
      alert(`'${CONFIRM_PHRASE}'를 정확히 입력해 주세요.`);
      return;
    }
    if (!window.confirm("정말로 계정을 삭제하시겠습니까? 이 작업은 되돌릴 수 없습니다.")) {
      return;
    }
    setIsDeleting(true);
    try {
      await axios.delete("/api/v1/user/me");
      localStorage.removeItem("token");
      localStorage.removeItem("refresh_token");
      alert("계정이 삭제되었습니다.");
      navigate("/");
      window.location.reload();
    } catch (error) {
      console.error("계정 삭제 실패:", error);
      alert(
        error.response?.data?.message || "계정 삭제에 실패했습니다. 잠시 후 다시 시도해 주세요."
      );
    } finally {
      setIsDeleting(false);
    }
  };

  return (
    <div
      style={{
        position: "relative",
        minHeight: "100vh",
        width: "100%",
        background: "linear-gradient(135deg, #0f172a 0%, #581c87 50%, #831843 100%)",
        overflow: "hidden",
      }}
    >
      {/* Animated Background Orbs */}
      <div
        style={{
          position: "absolute",
          top: "-100px",
          left: "-100px",
          width: "400px",
          height: "400px",
          background: "rgba(236, 72, 153, 0.2)",
          borderRadius: "50%",
          filter: "blur(80px)",
          animation: "pulse 4s ease-in-out infinite",
        }}
      />
      <div
        style={{
          position: "absolute",
          bottom: "-100px",
          right: "-100px",
          width: "400px",
          height: "400px",
          background: "rgba(139, 92, 246, 0.2)",
          borderRadius: "50%",
          filter: "blur(80px)",
          animation: "pulse 4s ease-in-out infinite",
          animationDelay: "1s",
        }}
      />

      {/* Dot Pattern Background */}
      <div
        style={{
          position: "absolute",
          inset: 0,
          backgroundImage: "radial-gradient(rgba(236, 72, 153, 0.1) 1px, transparent 1px)",
          backgroundSize: "32px 32px",
          maskImage: "radial-gradient(ellipse at center, black, transparent)",
        }}
      />

      {/* Main Content */}
      <div
        style={{
          position: "relative",
          zIndex: 10,
          maxWidth: "600px",
          margin: "0 auto",
          padding: "40px 20px",
        }}
      >
        {/* Back Button */}
        <motion.button
          initial={{ opacity: 0, x: -20 }}
          animate={{ opacity: 1, x: 0 }}
          transition={{ duration: 0.5 }}
          onClick={() => navigate(-1)}
          style={{
            display: "flex",
            alignItems: "center",
            gap: "8px",
            padding: "10px 16px",
            background: "rgba(255, 255, 255, 0.1)",
            backdropFilter: "blur(10px)",
            border: "1px solid rgba(255, 255, 255, 0.1)",
            borderRadius: "10px",
            color: "#fff",
            fontSize: "14px",
            fontWeight: 600,
            cursor: "pointer",
            marginBottom: "24px",
            transition: "all 0.2s ease",
          }}
          onMouseEnter={(e) => {
            e.currentTarget.style.background = "rgba(255, 255, 255, 0.15)";
          }}
          onMouseLeave={(e) => {
            e.currentTarget.style.background = "rgba(255, 255, 255, 0.1)";
          }}
        >
          <ArrowLeft size={18} />
          뒤로 가기
        </motion.button>

        {/* Header */}
        <motion.div
          initial={{ opacity: 0, y: -20 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ duration: 0.5, delay: 0.1 }}
          style={{ marginBottom: "32px" }}
        >
          <h1
            style={{
              fontSize: "32px",
              fontWeight: 800,
              background: "linear-gradient(135deg, #f472b6, #a78bfa)",
              WebkitBackgroundClip: "text",
              WebkitTextFillColor: "transparent",
              backgroundClip: "text",
              marginBottom: "8px",
            }}
          >
            계정 설정
          </h1>
          <p style={{ color: "rgba(148, 163, 184, 1)", fontSize: "15px" }}>
            프리미엄 계정 정보를 관리하세요
          </p>
        </motion.div>

        {/* Glassmorphism Card */}
        <motion.div
          initial={{ opacity: 0, y: 20 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ duration: 0.5, delay: 0.2 }}
          style={{
            backdropFilter: "blur(20px)",
            background: "rgba(255, 255, 255, 0.05)",
            border: "1px solid rgba(255, 255, 255, 0.1)",
            borderRadius: "20px",
            boxShadow: "0 25px 50px -12px rgba(0, 0, 0, 0.25)",
            overflow: "hidden",
          }}
        >
          {/* Profile Section */}
          <div style={{ padding: "32px", borderBottom: "1px solid rgba(255, 255, 255, 0.1)" }}>
            <div style={{ display: "flex", alignItems: "center", gap: "16px" }}>
              <div
                style={{
                  width: "80px",
                  height: "80px",
                  borderRadius: "50%",
                  background: "linear-gradient(135deg, #ec4899, #8b5cf6)",
                  display: "flex",
                  alignItems: "center",
                  justifyContent: "center",
                  boxShadow: "0 8px 24px rgba(236, 72, 153, 0.3)",
                }}
              >
                <User size={36} color="#fff" />
              </div>
              <div>
                <h3 style={{ color: "#fff", fontSize: "20px", fontWeight: 700, marginBottom: "4px" }}>
                  프리미엄 회원
                </h3>
                <p style={{ color: "rgba(148, 163, 184, 1)", fontSize: "14px" }}>
                  DVDHolic 서비스를 이용해 주셔서 감사합니다
                </p>
              </div>
            </div>
          </div>

          {/* Danger Zone */}
          <div style={{ padding: "32px" }}>
            <div style={{ display: "flex", alignItems: "center", gap: "8px", marginBottom: "16px" }}>
              <AlertTriangle size={20} color="#f87171" />
              <h3 style={{ color: "#f87171", fontSize: "18px", fontWeight: 700 }}>
                위험 구역
              </h3>
            </div>

            <div
              style={{
                background: "rgba(239, 68, 68, 0.1)",
                border: "1px solid rgba(239, 68, 68, 0.3)",
                borderRadius: "16px",
                padding: "24px",
              }}
            >
              <h4 style={{ color: "#fff", fontSize: "16px", fontWeight: 600, marginBottom: "8px" }}>
                회원 탈퇴
              </h4>
              <p style={{ color: "rgba(148, 163, 184, 1)", fontSize: "14px", lineHeight: 1.6, marginBottom: "20px" }}>
                계정을 삭제하면 모든 데이터가 영구적으로 삭제되며, 복구할 수 없습니다.
                탈퇴를 원하시면 아래에 <strong style={{ color: "#f87171" }}>"{CONFIRM_PHRASE}"</strong>를 입력해 주세요.
              </p>

              <div style={{ marginBottom: "16px" }}>
                <label
                  style={{
                    display: "block",
                    color: "#fff",
                    fontSize: "14px",
                    fontWeight: 500,
                    marginBottom: "8px",
                  }}
                >
                  확인 문구 입력
                </label>
                <input
                  type="text"
                  value={confirmText}
                  onChange={(e) => setConfirmText(e.target.value)}
                  placeholder={CONFIRM_PHRASE}
                  style={{
                    width: "100%",
                    padding: "14px 16px",
                    background: "rgba(255, 255, 255, 0.05)",
                    border: confirmText === CONFIRM_PHRASE 
                      ? "2px solid #f87171" 
                      : "1px solid rgba(255, 255, 255, 0.1)",
                    borderRadius: "12px",
                    color: "#fff",
                    fontSize: "15px",
                    outline: "none",
                    transition: "all 0.2s ease",
                    boxSizing: "border-box",
                  }}
                  onFocus={(e) => {
                    e.target.style.borderColor = "rgba(248, 113, 113, 0.5)";
                    e.target.style.boxShadow = "0 0 0 3px rgba(248, 113, 113, 0.2)";
                  }}
                  onBlur={(e) => {
                    e.target.style.borderColor = confirmText === CONFIRM_PHRASE 
                      ? "#f87171" 
                      : "rgba(255, 255, 255, 0.1)";
                    e.target.style.boxShadow = "none";
                  }}
                />
              </div>

              <motion.button
                whileHover={confirmText === CONFIRM_PHRASE && !isDeleting ? { scale: 1.02 } : {}}
                whileTap={confirmText === CONFIRM_PHRASE && !isDeleting ? { scale: 0.98 } : {}}
                onClick={handleDeleteAccount}
                disabled={confirmText !== CONFIRM_PHRASE || isDeleting}
                style={{
                  width: "100%",
                  padding: "14px",
                  background: confirmText === CONFIRM_PHRASE
                    ? "linear-gradient(135deg, #dc2626, #991b1b)"
                    : "rgba(255, 255, 255, 0.05)",
                  border: "none",
                  borderRadius: "12px",
                  color: confirmText === CONFIRM_PHRASE ? "#fff" : "rgba(148, 163, 184, 1)",
                  fontSize: "15px",
                  fontWeight: 700,
                  cursor: confirmText === CONFIRM_PHRASE && !isDeleting ? "pointer" : "not-allowed",
                  opacity: isDeleting ? 0.7 : 1,
                  display: "flex",
                  alignItems: "center",
                  justifyContent: "center",
                  gap: "8px",
                  transition: "all 0.2s ease",
                }}
              >
                {isDeleting ? (
                  "처리 중..."
                ) : (
                  <>
                    <Trash2 size={18} />
                    계정 삭제
                  </>
                )}
              </motion.button>
            </div>
          </div>
        </motion.div>

        {/* Footer */}
        <motion.div
          initial={{ opacity: 0 }}
          animate={{ opacity: 1 }}
          transition={{ duration: 0.5, delay: 0.4 }}
          style={{ marginTop: "32px", textAlign: "center" }}
        >
          <p style={{ color: "rgba(148, 163, 184, 1)", fontSize: "14px" }}>
            도움이 필요하신가요?{" "}
            <button
              onClick={() => navigate("/support")}
              style={{
                background: "none",
                border: "none",
                color: "#f472b6",
                fontSize: "14px",
                fontWeight: 500,
                cursor: "pointer",
                textDecoration: "underline",
              }}
            >
              고객 지원
            </button>
          </p>
        </motion.div>
      </div>

      <style>{`
        @keyframes pulse {
          0%, 100% { opacity: 0.5; transform: scale(1); }
          50% { opacity: 0.8; transform: scale(1.05); }
        }
      `}</style>
    </div>
  );
}

export default Account;
