import React, { useState, useEffect } from "react";
import { useLocation, useNavigate } from "react-router-dom";
import { Undo2 } from "lucide-react";
import axios from "../axiosConfig";
import "bootstrap/dist/css/bootstrap.min.css";

const baseUrl = "https://image.tmdb.org/t/p/original";
const palette = {
  text: "var(--ds-text)",
  textMuted: "var(--ds-text-muted)",
  border: "var(--ds-border)",
  panel: "var(--ds-panel)",
};

function MovieImages() {
  const location = useLocation();
  const navigateTo = useNavigate();
  const state = location.state || {};
  const fromPath = state.from || null;
  const fromLabel = state.fromLabel || "뒤로";

  const [movie, setMovie] = useState(state.movie || null);
  const [detailLoading, setDetailLoading] = useState(false);

  useEffect(() => {
    const m = state.movie;
    if (!m?.movieName) return;
    const isMinimal = !m.overview && !m.backdropPath && !m.genre;
    if (!isMinimal) return;
    setDetailLoading(true);
    axios.get(`/api/v1/movie/${encodeURIComponent(m.movieName)}/detail`)
      .then((res) => {
        if (res.data?.success && res.data.data) {
          setMovie(res.data.data);
        }
      })
      .catch(() => {})
      .finally(() => setDetailLoading(false));
  }, []);

  const [likeCount, setLikeCount] = useState(0);
  const [unlikeCount, setUnlikeCount] = useState(0);
  const [mehCount, setMehCount] = useState(0);
  const [myVote, setMyVote] = useState(null);
  const [voteLoading, setVoteLoading] = useState(false);
  const [voteError, setVoteError] = useState(null);
  const [voteFeedback, setVoteFeedback] = useState(null);

  const movieName = movie?.movieName;
  const posterPath = movie?.posterPath;
  const backdropPath = movie?.backdropPath;
  const contentType = movie?.contentType || "dvd";
  const ct = contentType;

  const hasPoster = !!posterPath;
  const hasBackdrop = !!backdropPath;
  const [activeTab, setActiveTab] = useState(hasPoster ? "poster" : "backdrop");

  useEffect(() => {
    if (hasPoster) setActiveTab("poster");
    else if (hasBackdrop) setActiveTab("backdrop");
  }, [hasPoster, hasBackdrop]);

  const refreshCounts = async (noCache = false) => {
    if (!movieName) return;
    const suffix = noCache ? `&_=${Date.now()}` : "";
    const results = await Promise.allSettled([
      axios.get(`/api/v1/movie/${encodeURIComponent(movieName)}/like-count?contentType=${ct}${suffix}`),
      axios.get(`/api/v1/movie/${encodeURIComponent(movieName)}/unlike-count?contentType=${ct}${suffix}`),
      axios.get(`/api/v1/movie/${encodeURIComponent(movieName)}/meh-count?contentType=${ct}${suffix}`),
      axios.get(`/api/v1/movie/${encodeURIComponent(movieName)}/my-vote?contentType=${ct}${suffix}`),
    ]);
    const likeVal = results[0].status === "fulfilled" && results[0].value.data?.success ? results[0].value.data.data : 0;
    const unlikeVal = results[1].status === "fulfilled" && results[1].value.data?.success ? results[1].value.data.data : 0;
    const mehVal = results[2].status === "fulfilled" && results[2].value.data?.success ? results[2].value.data.data : 0;
    const mv = results[3].status === "fulfilled" && results[3].value.data?.success ? results[3].value.data.data : null;
    setLikeCount(likeVal);
    setUnlikeCount(unlikeVal);
    setMehCount(mehVal);
    setMyVote(mv);
  };

  const showFeedback = (msg) => {
    setVoteFeedback(msg);
    setTimeout(() => setVoteFeedback(null), 2500);
  };

  useEffect(() => {
    if (!movieName) return;
    refreshCounts();
  }, [movieName, ct]);

  const like = async () => {
    if (!movieName) return;
    setVoteError(null);
    setVoteLoading(true);
    try {
      await axios.post(`/api/v1/movie/${encodeURIComponent(movieName)}/like?contentType=${ct}`);
      await refreshCounts(true);
    } catch (e) {
      console.error("좋아요 실패:", e);
      const msg = e.response?.data?.message || e.message || "요청 실패";
      setVoteError(`좋아요 실패: ${msg}`);
    } finally {
      setVoteLoading(false);
    }
  };
  const unlike = async () => {
    if (!movieName) return;
    setVoteError(null);
    setVoteLoading(true);
    try {
      await axios.post(`/api/v1/movie/${encodeURIComponent(movieName)}/unlike?contentType=${ct}`);
      await refreshCounts(true);
    } catch (e) {
      console.error("싫어요 실패:", e);
      const msg = e.response?.data?.message || e.message || "요청 실패";
      setVoteError(`싫어요 실패: ${msg}`);
    } finally {
      setVoteLoading(false);
    }
  };

  const meh = async () => {
    if (!movieName) return;
    setVoteError(null);
    setVoteLoading(true);
    try {
      await axios.post(`/api/v1/movie/${encodeURIComponent(movieName)}/meh?contentType=${ct}`);
      await refreshCounts(true);
    } catch (e) {
      console.error("꿀꿀해 실패:", e);
      const msg = e.response?.data?.message || e.message || "요청 실패";
      setVoteError(`꿀꿀해 실패: ${msg}`);
    } finally {
      setVoteLoading(false);
    }
  };

  const getYouTubeUrl = (m) => {
    if (!m) return "";
    if (m.trailerUrl && String(m.trailerUrl).trim() !== "") return m.trailerUrl;
    return `https://www.youtube.com/results?search_query=${encodeURIComponent((m.movieName || "") + " 예고편")}`;
  };

  const isCorruptedKorean = (text) => {
    if (!text) return false;
    return /[\u4E00-\u9FFF]/.test(text);
  };

  const getDisplayOverview = (overview) => {
    const noDesc = ct === "movie" ? "이 영화, 말이 없네요 🤐" : "이 DVD, 말이 없네요 🤐";
    if (!overview || overview.trim() === "" || overview === "No description available.") return noDesc;
    if (isCorruptedKorean(overview)) return noDesc;
    return overview;
  };

  const formatGenreForDisplay = (value) => {
    const raw = String(value ?? "").trim();
    if (!raw) return "";
    if (raw.length <= 28) return raw;
    return raw.split(",").map((i) => i.trim()).filter(Boolean).join(",\n");
  };

  const getOneLineMeta = (m) => {
    if (!m) return "";
    const parts = [];
    const year = (m.releaseDate || m.releasedAt || "").slice(0, 4);
    if (year) parts.push(year);
    if (m.runtime) parts.push(`${m.runtime}분`);
    if (m.certification) parts.push(m.certification);
    return parts.join(" · ");
  };

  const isRecentRelease = (m) => {
    const dateStr = m?.releaseDate || m?.releasedAt || "";
    const year = parseInt(dateStr.slice(0, 4), 10);
    return !isNaN(year) && year >= new Date().getFullYear() - 1;
  };

  const formatVoteCount = (n) => {
    if (!n || n <= 0) return null;
    if (n >= 10000) return `${(n / 10000).toFixed(1)}만 명`;
    if (n >= 1000) return `${(n / 1000).toFixed(1)}천 명`;
    return `${n.toLocaleString()}명`;
  };

  const formatCurrency = (n) => {
    if (!n || n <= 0) return null;
    if (n >= 1e9) return `$${(n / 1e9).toFixed(1)}B`;
    if (n >= 1e6) return `$${(n / 1e6).toFixed(0)}M`;
    if (n >= 1e3) return `$${(n / 1e3).toFixed(0)}K`;
    return `$${n.toLocaleString()}`;
  };

  if (detailLoading) {
    return (
      <div style={{ padding: "60px 24px", textAlign: "center", color: palette.textMuted, minHeight: "100vh", background: "#09090b" }}>
        <div style={{ width: "40px", height: "40px", border: "3px solid rgba(255,59,92,0.2)", borderTopColor: "#ff3b5c", borderRadius: "50%", margin: "0 auto 16px", animation: "spin 1s linear infinite" }} />
        <p>영화 정보를 불러오는 중...</p>
        <style>{`@keyframes spin { from { transform: rotate(0deg); } to { transform: rotate(360deg); } }`}</style>
      </div>
    );
  }

  if (!movie || !movieName) {
    return (
      <div style={{ padding: "24px", textAlign: "center", color: palette.textMuted }}>
        <p>영화 정보를 찾을 수 없습니다.</p>
      </div>
    );
  }

  return (
    <div
      style={{
        minHeight: "100vh",
        background: "radial-gradient(1200px 600px at 20% -10%, rgba(255,59,92,0.12), transparent), radial-gradient(1000px 500px at 100% -20%, rgba(91,140,255,0.12), transparent), #09090b",
        padding: "20px 16px 40px",
      }}
    >
      {fromPath && (
        <div style={{ maxWidth: "800px", margin: "0 auto 12px" }}>
          <button
            type="button"
            onClick={() => navigateTo(fromPath)}
            title={fromLabel}
            style={{
              display: "inline-flex",
              alignItems: "center",
              justifyContent: "center",
              width: "40px",
              height: "40px",
              padding: 0,
              background: "linear-gradient(135deg, rgba(255,59,92,0.15), rgba(91,140,255,0.15))",
              border: "1px solid rgba(255,255,255,0.12)",
              borderRadius: "50%",
              color: "rgba(255,255,255,0.85)",
              cursor: "pointer",
              transition: "all 0.25s ease",
              boxShadow: "0 2px 8px rgba(0,0,0,0.2)",
            }}
            onMouseEnter={(e) => {
              e.currentTarget.style.background = "linear-gradient(135deg, rgba(255,59,92,0.3), rgba(91,140,255,0.3))";
              e.currentTarget.style.transform = "scale(1.1)";
              e.currentTarget.style.boxShadow = "0 4px 16px rgba(255,59,92,0.25)";
            }}
            onMouseLeave={(e) => {
              e.currentTarget.style.background = "linear-gradient(135deg, rgba(255,59,92,0.15), rgba(91,140,255,0.15))";
              e.currentTarget.style.transform = "scale(1)";
              e.currentTarget.style.boxShadow = "0 2px 8px rgba(0,0,0,0.2)";
            }}
          >
            <Undo2 size={20} strokeWidth={2.5} />
          </button>
        </div>
      )}
      <h1 style={{ color: palette.text, fontSize: "22px", fontWeight: 800, marginBottom: "24px", textAlign: "center" }}>
        {movieName}
      </h1>

      {/* 포스터/배경 탭 */}
      {(hasPoster || hasBackdrop) && (
        <div
          style={{
            display: "flex",
            gap: "8px",
            marginBottom: "20px",
            maxWidth: "800px",
            margin: "0 auto 20px auto",
            borderBottom: `2px solid ${palette.border}`,
          }}
        >
          {hasPoster && (
            <button
              type="button"
              onClick={() => setActiveTab("poster")}
              style={{
                padding: "12px 24px",
                border: "none",
                borderBottom: activeTab === "poster" ? "3px solid #ff3b5c" : "3px solid transparent",
                marginBottom: "-2px",
                background: "transparent",
                color: activeTab === "poster" ? palette.text : palette.textMuted,
                fontSize: "15px",
                fontWeight: 600,
                cursor: "pointer",
              }}
            >
              포스터
            </button>
          )}
          {hasBackdrop && (
            <button
              type="button"
              onClick={() => setActiveTab("backdrop")}
              style={{
                padding: "12px 24px",
                border: "none",
                borderBottom: activeTab === "backdrop" ? "3px solid #ff3b5c" : "3px solid transparent",
                marginBottom: "-2px",
                background: "transparent",
                color: activeTab === "backdrop" ? palette.text : palette.textMuted,
                fontSize: "15px",
                fontWeight: 600,
                cursor: "pointer",
              }}
            >
              배경 이미지
            </button>
          )}
        </div>
      )}

      {/* 이미지 영역 */}
      <div style={{ maxWidth: "800px", margin: "0 auto 24px" }}>
        {activeTab === "poster" && posterPath && (
          <img
            src={`${baseUrl}${posterPath}`}
            alt={`${movieName} 포스터`}
            style={{ width: "100%", borderRadius: "12px", boxShadow: "0 8px 24px rgba(0,0,0,0.4)" }}
            draggable={false}
          />
        )}
        {activeTab === "backdrop" && backdropPath && (
          <img
            src={`${baseUrl}${backdropPath}`}
            alt={`${movieName} 배경`}
            style={{ width: "100%", borderRadius: "12px", boxShadow: "0 8px 24px rgba(0,0,0,0.4)" }}
            draggable={false}
          />
        )}
        {!posterPath && !backdropPath && (
          <img src="/no-poster-placeholder.png" alt="이미지 없음" style={{ width: "100%", maxWidth: "400px", margin: "0 auto", display: "block", borderRadius: "12px" }} />
        )}
      </div>

      {/* 상세 정보 */}
      <div style={{ maxWidth: "600px", margin: "0 auto" }}>
        {/* 한 줄 메타 + 배지 */}
        {(getOneLineMeta(movie) || movie.voteAverage >= 7.5 || isRecentRelease(movie)) && (
          <div style={{ padding: "10px 15px 12px", borderBottom: `1px solid ${palette.border}`, display: "flex", flexWrap: "wrap", gap: "8px", justifyContent: "center", marginBottom: "12px" }}>
            {getOneLineMeta(movie) && <span style={{ color: palette.textMuted, fontSize: "13px", fontWeight: 500 }}>{getOneLineMeta(movie)}</span>}
            {movie.voteAverage >= 7.5 && <span style={{ padding: "3px 8px", borderRadius: "4px", fontSize: "11px", fontWeight: 700, backgroundColor: "rgba(229, 193, 0, 0.2)", color: "#E5C100", border: "1px solid rgba(229, 193, 0, 0.4)" }}>⭐ 높은 평점</span>}
            {isRecentRelease(movie) && <span style={{ padding: "3px 8px", borderRadius: "4px", fontSize: "11px", fontWeight: 700, backgroundColor: "rgba(0, 200, 83, 0.2)", color: "#00C853", border: "1px solid rgba(0, 200, 83, 0.4)" }}>🆕 최신</span>}
          </div>
        )}

        {/* 태그라인 */}
        {movie.tagline && movie.tagline.trim() !== "" && (
          <div style={{ padding: "8px 15px 12px", borderBottom: `1px solid ${palette.border}`, textAlign: "center", marginBottom: "12px" }}>
            <span style={{ color: palette.textMuted, fontSize: "14px", fontStyle: "italic" }}>"{movie.tagline}"</span>
          </div>
        )}

        {/* OTT */}
        <div style={{ padding: "18px 15px", backgroundColor: "rgba(0,150,136,0.15)", border: "1px solid rgba(0,200,180,0.4)", borderLeft: "4px solid #00C853", borderRadius: "8px", marginBottom: "12px" }}>
          <span style={{ color: palette.text, fontSize: "15px", fontWeight: 800, marginBottom: "8px", display: "block" }}>📺 시청 가능한 플랫폼</span>
          {movie.ottProviders && movie.ottProviders.trim() ? (
            <div style={{ display: "flex", flexWrap: "wrap", gap: "8px", marginBottom: "12px" }}>
              {movie.ottProviders.split(/[,·]/).map((p, i) => (
                <span key={i} style={{ padding: "6px 12px", background: "rgba(255,255,255,0.12)", borderRadius: "6px", fontSize: "14px", fontWeight: 600, color: "#00E676" }}>{p.trim()}</span>
              ))}
            </div>
          ) : (
            <p style={{ color: palette.textMuted, fontSize: "14px", margin: "0 0 12px 0" }}>등록된 OTT 정보가 없습니다.</p>
          )}
          {movie.movieName && (
            <a href={getYouTubeUrl(movie)} rel="noopener noreferrer" style={{ display: "inline-flex", alignItems: "center", gap: "6px", color: "inherit", fontSize: "15px", fontWeight: 700, textDecoration: "none" }}>
              <span style={{ display: "inline-flex", alignItems: "center", justifyContent: "center", width: 24, height: 24, borderRadius: 4, backgroundColor: "#E62117", color: "#fff", fontSize: "10px", lineHeight: 1, paddingLeft: 2 }}>▶</span>
              <span style={{ color: "#fff", fontWeight: 600, letterSpacing: "-0.5px" }}>YouTube</span>
              <span style={{ color: "#00E676" }}>예고편 보기</span>
            </a>
          )}
        </div>

        {/* 줄거리 */}
        <div style={{ padding: "15px", color: palette.text, fontSize: "13px", lineHeight: "1.6", borderBottom: `1px solid ${palette.border}`, textAlign: "center", marginBottom: "12px" }}>
          {getDisplayOverview(movie.overview)}
        </div>

        {/* 상세 정보 */}
        <div style={{ padding: "15px", backgroundColor: "#0f131c", borderRadius: "8px", marginBottom: "12px", fontFamily: "-apple-system, BlinkMacSystemFont, 'Segoe UI', system-ui, sans-serif" }}>
          <div style={{ display: "flex", flexDirection: "column", gap: "12px", alignItems: "center" }}>
            <div style={{ display: "flex", gap: "8px", flexWrap: "wrap", justifyContent: "center" }}>
              <span style={{ padding: "5px 10px", borderRadius: "999px", fontSize: "12px", fontWeight: 700, color: "#fff", backgroundColor: "rgba(255,255,255,0.08)", border: `1px solid ${palette.border}` }}>콘텐츠 유형: {(movie.contentType || "-").toUpperCase()}</span>
              {typeof movie.isAdult === "boolean" && <span style={{ padding: "5px 10px", borderRadius: "999px", fontSize: "12px", fontWeight: 700, color: "#fff", backgroundColor: movie.isAdult ? "rgba(229, 9, 20, 0.35)" : "rgba(76, 175, 80, 0.25)", border: `1px solid ${palette.border}` }}>{movie.isAdult ? "성인 등급" : "일반 등급"}</span>}
            </div>
            {movie.voteAverage && (
              <div style={{ width: "100%", display: "flex", flexDirection: "column", gap: "5px" }}>
                <div style={{ display: "flex", alignItems: "center", gap: "15px" }}>
                  <span style={{ color: "#fff", fontSize: "20px", fontWeight: "bold", width: "80px", flexShrink: 0, whiteSpace: "nowrap" }}>⭐ 평점</span>
                  <span style={{ color: "#fff", fontSize: "20px", fontWeight: 300, flex: 1, minWidth: 0 }}>{movie.voteAverage.toFixed(1)} / 10 {formatVoteCount(movie.voteCount) && <span style={{ color: palette.textMuted, fontSize: "14px", marginLeft: "8px" }}>({formatVoteCount(movie.voteCount)} 평가)</span>}</span>
                </div>
              </div>
            )}
            {movie.releaseDate && <div style={{ display: "flex", alignItems: "center", gap: "15px", width: "100%" }}><span style={{ color: "#fff", fontSize: "20px", fontWeight: "bold", width: "80px", flexShrink: 0, whiteSpace: "nowrap" }}>📅 {ct === "movie" ? "개봉일" : "발매일"}</span><span style={{ color: "#fff", fontSize: "20px", fontWeight: 300, flex: 1, minWidth: 0 }}>{movie.releaseDate}</span></div>}
            {!movie.releaseDate && movie.releasedAt && <div style={{ display: "flex", alignItems: "center", gap: "15px", width: "100%" }}><span style={{ color: "#fff", fontSize: "20px", fontWeight: "bold", width: "80px", flexShrink: 0, whiteSpace: "nowrap" }}>📅 공개일</span><span style={{ color: "#fff", fontSize: "20px", fontWeight: 300, flex: 1, minWidth: 0 }}>{movie.releasedAt}</span></div>}
            {movie.runtime && <div style={{ display: "flex", alignItems: "center", gap: "24px", width: "100%" }}><span style={{ color: "#fff", fontSize: "20px", fontWeight: "bold", width: "100px", flexShrink: 0, whiteSpace: "nowrap" }}>⏱️ 상영시간</span><span style={{ color: "#fff", fontSize: "20px", fontWeight: 300, flex: 1, minWidth: 0 }}>{movie.runtime}분</span></div>}
            {movie.genre && <div style={{ display: "flex", alignItems: "flex-start", gap: "15px", width: "100%" }}><span style={{ color: "#fff", fontSize: "20px", fontWeight: "bold", width: "80px", flexShrink: 0, whiteSpace: "nowrap" }}>🎭 장르</span><span style={{ color: "#fff", fontSize: "20px", fontWeight: 300, whiteSpace: "pre-line", flex: 1, minWidth: 0 }}>{formatGenreForDisplay(movie.genre)}</span></div>}
            {movie.director && <div style={{ display: "flex", alignItems: "flex-start", gap: "15px", width: "100%" }}><span style={{ color: "#fff", fontSize: "20px", fontWeight: "bold", width: "80px", flexShrink: 0, whiteSpace: "nowrap" }}>🎬 감독</span><span style={{ color: "#fff", fontSize: "20px", fontWeight: 300, flex: 1, minWidth: 0 }}>{movie.director}</span></div>}
            {movie.cast && <div style={{ display: "flex", alignItems: "flex-start", gap: "15px", width: "100%" }}><span style={{ color: "#fff", fontSize: "20px", fontWeight: "bold", width: "80px", flexShrink: 0, whiteSpace: "nowrap" }}>🎭 출연</span><span style={{ color: "#fff", fontSize: "20px", lineHeight: 1.5, fontWeight: 300, flex: 1, minWidth: 0 }}>{movie.cast}</span></div>}
            {movie.certification && <div style={{ display: "flex", alignItems: "center", gap: "15px", width: "100%" }}><span style={{ color: "#fff", fontSize: "20px", fontWeight: "bold", width: "80px", flexShrink: 0, whiteSpace: "nowrap" }}>🔞 등급</span><span style={{ color: "#fff", fontSize: "20px", fontWeight: 300, flex: 1, minWidth: 0 }}>{movie.certification}</span></div>}
            {movie.productionCountries && <div style={{ display: "flex", alignItems: "center", gap: "15px", width: "100%" }}><span style={{ color: "#fff", fontSize: "20px", fontWeight: "bold", width: "80px", flexShrink: 0, whiteSpace: "nowrap" }}>🌍 제작국</span><span style={{ color: "#fff", fontSize: "20px", fontWeight: 300, flex: 1, minWidth: 0 }}>{movie.productionCountries}</span></div>}
            {movie.productionCompanies && <div style={{ display: "flex", alignItems: "center", gap: "15px", width: "100%" }}><span style={{ color: "#fff", fontSize: "20px", fontWeight: "bold", width: "80px", flexShrink: 0, whiteSpace: "nowrap" }}>🏢 제작사</span><span style={{ color: "#fff", fontSize: "20px", fontWeight: 300, flex: 1, minWidth: 0 }}>{movie.productionCompanies}</span></div>}
            {movie.budget != null && movie.budget > 0 && <div style={{ display: "flex", alignItems: "center", gap: "24px", width: "100%" }}><span style={{ color: "#fff", fontSize: "20px", fontWeight: "bold", width: "100px", flexShrink: 0, whiteSpace: "nowrap" }}>💰 예산</span><span style={{ color: "#fff", fontSize: "20px", fontWeight: 300, flex: 1, minWidth: 0 }}>{formatCurrency(movie.budget)}</span></div>}
            {movie.revenue != null && movie.revenue > 0 && <div style={{ display: "flex", alignItems: "center", gap: "24px", width: "100%" }}><span style={{ color: "#fff", fontSize: "20px", fontWeight: "bold", width: "100px", flexShrink: 0, whiteSpace: "nowrap" }}>📈 흥행 수익</span><span style={{ color: "#fff", fontSize: "20px", fontWeight: 300, flex: 1, minWidth: 0 }}>{formatCurrency(movie.revenue)}</span></div>}
            {movie.collection && <div style={{ display: "flex", alignItems: "center", gap: "15px", width: "100%" }}><span style={{ color: "#fff", fontSize: "20px", fontWeight: "bold", width: "80px", flexShrink: 0, whiteSpace: "nowrap" }}>📚 시리즈</span><span style={{ color: "#fff", fontSize: "20px", fontWeight: 300, flex: 1, minWidth: 0 }}>{movie.collection}</span></div>}
            {movie.spokenLanguages && <div style={{ display: "flex", alignItems: "flex-start", gap: "24px", width: "100%" }}><span style={{ color: "#fff", fontSize: "20px", fontWeight: "bold", width: "100px", flexShrink: 0, whiteSpace: "nowrap" }}>🗣️ 상영 언어</span><span style={{ color: "#fff", fontSize: "20px", fontWeight: 300, flex: 1, minWidth: 0, wordBreak: "break-word" }}>{movie.spokenLanguages}</span></div>}
            {movie.homepage && <div style={{ display: "flex", alignItems: "center", gap: "15px", width: "100%" }}><span style={{ color: "#fff", fontSize: "20px", fontWeight: "bold", width: "80px", flexShrink: 0, whiteSpace: "nowrap" }}>🔗 공식 홈페이지</span><a href={movie.homepage} target="_blank" rel="noopener noreferrer" style={{ color: "#5C6BC0", fontSize: "18px", fontWeight: 600, textDecoration: "none", flex: 1, minWidth: 0 }}>바로가기 →</a></div>}
            {movie.originalTitle && movie.originalTitle !== movie.movieName && <div style={{ display: "flex", alignItems: "center", gap: "15px", width: "100%" }}><span style={{ color: "#fff", fontSize: "20px", fontWeight: "bold", width: "80px", flexShrink: 0, whiteSpace: "nowrap" }}>🌐 원제</span><span style={{ color: "#fff", fontSize: "18px", fontWeight: 300, flex: 1, minWidth: 0 }}>{movie.originalTitle}</span></div>}
            {movie.imdbId && <div style={{ display: "flex", alignItems: "center", gap: "15px", width: "100%" }}><span style={{ color: "#fff", fontSize: "20px", fontWeight: "bold", width: "80px", flexShrink: 0, whiteSpace: "nowrap" }}>📎 IMDB</span><a href={`https://www.imdb.com/title/${movie.imdbId}`} target="_blank" rel="noopener noreferrer" style={{ color: "#F5C518", fontSize: "18px", fontWeight: 600, textDecoration: "none", flex: 1, minWidth: 0 }}>IMDB에서 상세보기 →</a></div>}
          </div>
        </div>

        {/* 좋아요/싫어요 */}
        <div style={{ display: "flex", flexDirection: "column", alignItems: "center", gap: "8px" }}>
          {voteError && (
            <div style={{ padding: "8px 12px", background: "rgba(255,59,92,0.2)", color: "#ff3b5c", borderRadius: "8px", fontSize: "13px", maxWidth: "100%" }}>
              {voteError}
            </div>
          )}
          {voteFeedback && (
            <div style={{ padding: "8px 12px", background: "rgba(0,200,83,0.2)", color: "#00C853", borderRadius: "8px", fontSize: "13px", maxWidth: "100%" }}>
              {voteFeedback}
            </div>
          )}
          {/* 좋아요/싫어요/꿀꿀해 각각 토글: 같은 버튼 다시 누르면 취소 */}
          <div style={{ display: "flex", justifyContent: "space-around", alignItems: "flex-start", padding: "12px", gap: "10px", flexWrap: "wrap" }}>
          <div style={{ display: "flex", flexDirection: "column", alignItems: "center", gap: "4px" }}>
            <button onClick={like} disabled={voteLoading} style={{ border: "none", background: "none", padding: 0, width: 36, height: 36, cursor: voteLoading ? "wait" : "pointer", opacity: voteLoading ? 0.6 : 1, display: "flex", alignItems: "center", justifyContent: "center" }}>
              <img src="https://img.icons8.com/emoji/96/red-heart.png" alt="좋아요" style={{ width: 36, height: 36, objectFit: "contain" }} />
            </button>
            <span style={{ color: "#fff", fontSize: "12px", fontWeight: "bold" }}>{likeCount}</span>
          </div>
          <div style={{ display: "flex", flexDirection: "column", alignItems: "center", gap: "4px" }}>
            <button onClick={unlike} disabled={voteLoading} style={{ border: "none", background: "none", padding: 0, width: 36, height: 36, cursor: voteLoading ? "wait" : "pointer", opacity: voteLoading ? 0.6 : 1, display: "flex", alignItems: "center", justifyContent: "center" }}>
              <img src="https://img.icons8.com/fluency/96/thumbs-down.png" alt="싫어요" style={{ width: 36, height: 36, objectFit: "contain" }} />
            </button>
            <span style={{ color: "#fff", fontSize: "12px", fontWeight: "bold" }}>{unlikeCount}</span>
          </div>
          <div style={{ display: "flex", flexDirection: "column", alignItems: "center", gap: "4px" }}>
            <button onClick={meh} disabled={voteLoading} style={{ border: "none", background: "none", padding: 0, width: 36, height: 36, cursor: voteLoading ? "wait" : "pointer", opacity: voteLoading ? 0.6 : 1, display: "flex", alignItems: "center", justifyContent: "center" }}>
              <img src="/kaonashi.png" alt="꿀꿀해" style={{ width: 36, height: 36, objectFit: "contain" }} />
            </button>
            <span style={{ color: "#fff", fontSize: "12px", fontWeight: "bold" }}>{mehCount}</span>
          </div>
          <div style={{ display: "flex", flexDirection: "column", alignItems: "center", gap: "6px" }}>
            <div style={{ display: "flex", alignItems: "center", gap: "6px" }}>
              <span style={{ color: "#fff", fontSize: "12px", fontWeight: "bold", minWidth: 42, textAlign: "right" }}>좋아요</span>
              <div style={{ width: 64, height: 10, backgroundColor: "#333", borderRadius: 4, overflow: "hidden" }}>
                <div style={{ width: `${likeCount + unlikeCount + mehCount > 0 ? (likeCount / (likeCount + unlikeCount + mehCount)) * 100 : 0}%`, height: "100%", backgroundColor: "#ff0000", borderRadius: 4, transition: "none" }} />
              </div>
              <span style={{ color: "#fff", fontSize: "11px", fontWeight: "bold", minWidth: 20 }}>{likeCount}</span>
            </div>
            <div style={{ display: "flex", alignItems: "center", gap: "6px" }}>
              <span style={{ color: "#fff", fontSize: "12px", fontWeight: "bold", minWidth: 42, textAlign: "right" }}>싫어요</span>
              <div style={{ width: 64, height: 10, backgroundColor: "#333", borderRadius: 4, overflow: "hidden" }}>
                <div style={{ width: `${likeCount + unlikeCount + mehCount > 0 ? (unlikeCount / (likeCount + unlikeCount + mehCount)) * 100 : 0}%`, height: "100%", backgroundColor: "#FFC107", borderRadius: 4, transition: "none" }} />
              </div>
              <span style={{ color: "#fff", fontSize: "11px", fontWeight: "bold", minWidth: 20 }}>{unlikeCount}</span>
            </div>
            <div style={{ display: "flex", alignItems: "center", gap: "6px" }}>
              <span style={{ color: "#fff", fontSize: "12px", fontWeight: "bold", minWidth: 42, textAlign: "right" }}>꿀꿀해</span>
              <div style={{ width: 64, height: 10, backgroundColor: "#333", borderRadius: 4, overflow: "hidden" }}>
                <div style={{ width: `${likeCount + unlikeCount + mehCount > 0 ? (mehCount / (likeCount + unlikeCount + mehCount)) * 100 : 0}%`, height: "100%", backgroundColor: "#9c27b0", borderRadius: 4, transition: "none" }} />
              </div>
              <span style={{ color: "#fff", fontSize: "11px", fontWeight: "bold", minWidth: 20 }}>{mehCount}</span>
            </div>
          </div>
          </div>
          {voteLoading && <span style={{ color: palette.textMuted, fontSize: "12px" }}>처리 중...</span>}
        </div>
      </div>
    </div>
  );
}

export default MovieImages;
