import React, { useState } from "react";
import { Link } from "react-router-dom";
import { motion, AnimatePresence } from "framer-motion";
import {
  Lock,
  Mail,
  Eye,
  EyeOff,
  Users,
  Activity,
  Shield,
  TrendingUp,
  Search,
  MoreHorizontal,
  LogOut,
  LayoutDashboard,
} from "lucide-react";
import axios from "../axiosConfig";

function LoginForm({ onLogin }) {
  const [adminId, setAdminId] = useState("");
  const [password, setPassword] = useState("");
  const [showPassword, setShowPassword] = useState(false);
  const [error, setError] = useState("");
  const [loading, setLoading] = useState(false);

  const handleLogin = async (e) => {
    e.preventDefault();
    setError("");
    if (!adminId.trim() || !password.trim()) {
      setError("아이디와 비밀번호를 입력해 주세요.");
      return;
    }
    setLoading(true);
    try {
      const res = await axios.post("/api/v1/admin/login", {
        adminId: adminId.trim(),
        password,
      });
      if (res.data?.success && res.data?.data?.token) {
        localStorage.setItem("adminToken", res.data.data.token);
        onLogin();
      } else {
        setError("로그인에 실패했습니다.");
      }
    } catch (err) {
      const msg = err.response?.data?.message || "로그인에 실패했습니다.";
      setError(msg);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div
      className="min-h-screen w-full flex items-center justify-center"
      style={{
        background: "linear-gradient(135deg, #ecfdf5 0%, #d1fae5 50%, #a7f3d0 100%)",
      }}
    >
      <motion.div
        initial={{ opacity: 0, y: 20 }}
        animate={{ opacity: 1, y: 0 }}
        transition={{ duration: 0.5 }}
        style={{ width: "100%", maxWidth: 420 }}
      >
        <div
          style={{
            background: "#fff",
            borderRadius: "16px",
            boxShadow: "0 25px 50px -12px rgba(0,0,0,0.15)",
            border: "2px solid rgba(16, 185, 129, 0.2)",
            overflow: "hidden",
          }}
        >
          <div style={{ padding: "32px 24px", textAlign: "center", borderBottom: "1px solid #e5e7eb" }}>
            <motion.div
              initial={{ scale: 0 }}
              animate={{ scale: 1 }}
              transition={{ delay: 0.2, type: "spring", stiffness: 200 }}
              style={{
                width: 64,
                height: 64,
                borderRadius: "16px",
                background: "linear-gradient(135deg, #10b981, #059669)",
                display: "flex",
                alignItems: "center",
                justifyContent: "center",
                margin: "0 auto 20px",
                boxShadow: "0 4px 14px rgba(16, 185, 129, 0.4)",
              }}
            >
              <Shield size={32} color="#fff" />
            </motion.div>
            <h1 style={{ fontSize: "24px", fontWeight: 700, color: "#047857", marginBottom: "8px" }}>
              사장님 전용
            </h1>
            <p style={{ fontSize: "14px", color: "#6b7280" }}>관리자 로그인</p>
          </div>
          <form onSubmit={handleLogin} style={{ padding: "24px" }}>
            <div style={{ marginBottom: "16px" }}>
              <div style={{ position: "relative" }}>
                <Mail
                  size={20}
                  style={{
                    position: "absolute",
                    left: 14,
                    top: "50%",
                    transform: "translateY(-50%)",
                    color: "#059669",
                  }}
                />
                <input
                  type="text"
                  placeholder="아이디"
                  value={adminId}
                  onChange={(e) => setAdminId(e.target.value)}
                  style={{
                    width: "100%",
                    height: 48,
                    padding: "0 14px 0 44px",
                    border: "2px solid #a7f3d0",
                    borderRadius: "10px",
                    fontSize: "15px",
                    outline: "none",
                  }}
                />
              </div>
            </div>
            <div style={{ marginBottom: "20px" }}>
              <div style={{ position: "relative" }}>
                <Lock
                  size={20}
                  style={{
                    position: "absolute",
                    left: 14,
                    top: "50%",
                    transform: "translateY(-50%)",
                    color: "#059669",
                  }}
                />
                <input
                  type={showPassword ? "text" : "password"}
                  placeholder="비밀번호"
                  value={password}
                  onChange={(e) => setPassword(e.target.value)}
                  style={{
                    width: "100%",
                    height: 48,
                    padding: "0 44px 0 44px",
                    border: "2px solid #a7f3d0",
                    borderRadius: "10px",
                    fontSize: "15px",
                    outline: "none",
                  }}
                />
                <button
                  type="button"
                  onClick={() => setShowPassword(!showPassword)}
                  style={{
                    position: "absolute",
                    right: 12,
                    top: "50%",
                    transform: "translateY(-50%)",
                    background: "none",
                    border: "none",
                    cursor: "pointer",
                    color: "#9ca3af",
                  }}
                >
                  {showPassword ? <EyeOff size={20} /> : <Eye size={20} />}
                </button>
              </div>
            </div>
            {error && (
              <motion.p
                initial={{ opacity: 0 }}
                animate={{ opacity: 1 }}
                style={{ color: "#dc2626", fontSize: "13px", marginBottom: "12px", textAlign: "center" }}
              >
                {error}
              </motion.p>
            )}
            <button
              type="submit"
              disabled={loading}
              style={{
                width: "100%",
                height: 48,
                background: "linear-gradient(135deg, #10b981, #059669)",
                color: "#fff",
                border: "none",
                borderRadius: "10px",
                fontSize: "16px",
                fontWeight: 600,
                cursor: loading ? "not-allowed" : "pointer",
                opacity: loading ? 0.7 : 1,
                boxShadow: "0 4px 14px rgba(16, 185, 129, 0.35)",
              }}
            >
              {loading ? "로그인 중..." : "로그인"}
            </button>
          </form>
        </div>
        <p style={{ textAlign: "center", marginTop: "20px", fontSize: "12px", color: "#6b7280" }}>
          <Link to="/" style={{ color: "#059669", textDecoration: "none" }}>
            홈으로 돌아가기
          </Link>
        </p>
      </motion.div>
    </div>
  );
}

function Dashboard({ onLogout }) {
  const [activeTab, setActiveTab] = useState("admins");
  const [searchQuery, setSearchQuery] = useState("");
  const [admins, setAdmins] = useState([]);
  const [users, setUsers] = useState([]);
  const [logs, setLogs] = useState([]);
  const [stats, setStats] = useState([]);
  const [loading, setLoading] = useState(true);

  React.useEffect(() => {
    const token = localStorage.getItem("adminToken");
    if (!token) return;
    const fetchAll = async () => {
      setLoading(true);
      try {
        const [a, u, l, s] = await Promise.allSettled([
          axios.get("/api/v1/admin/admins"),
          axios.get("/api/v1/admin/users"),
          axios.get("/api/v1/admin/access-logs"),
          axios.get("/api/v1/admin/daily-stats"),
        ]);
        const has401 = [a, u, l, s].some(
          (p) => p.status === "rejected" && p.reason?.response?.status === 401
        );
        if (has401) {
          localStorage.removeItem("adminToken");
          onLogout();
          return;
        }
        if (a.status === "fulfilled" && a.value?.data?.success) setAdmins(a.value.data.data || []);
        if (u.status === "fulfilled" && u.value?.data?.success) setUsers(u.value.data.data || []);
        if (l.status === "fulfilled" && l.value?.data?.success) setLogs(l.value.data.data || []);
        if (s.status === "fulfilled" && s.value?.data?.success) setStats(s.value.data.data || []);
      } catch (e) {
        if (e?.response?.status === 401) {
          localStorage.removeItem("adminToken");
          onLogout();
        } else {
          console.error("대시보드 데이터 로드 실패:", e);
        }
      } finally {
        setLoading(false);
      }
    };
    fetchAll();
  }, [onLogout]);

  const statsCards = [
    { title: "관리자", value: admins.length, icon: Shield, color: "linear-gradient(135deg, #10b981, #059669)" },
    { title: "회원", value: users.length, icon: Users, color: "linear-gradient(135deg, #3b82f6, #06b6d4)" },
    { title: "접속 로그", value: logs.length, icon: Activity, color: "linear-gradient(135deg, #8b5cf6, #ec4899)" },
    { title: "일별 통계", value: stats.length, icon: TrendingUp, color: "linear-gradient(135deg, #f59e0b, #ef4444)" },
  ];

  const filterList = (list, keys) => {
    if (!searchQuery.trim()) return list;
    const q = searchQuery.toLowerCase();
    return list.filter((row) =>
      keys.some((k) => String(row[k] || "").toLowerCase().includes(q))
    );
  };

  return (
    <div
      style={{
        minHeight: "100vh",
        background: "linear-gradient(135deg, #ecfdf5 0%, #d1fae5 50%, #a7f3d0 100%)",
      }}
    >
      <header
        style={{
          position: "sticky",
          top: 0,
          zIndex: 10,
          background: "rgba(255,255,255,0.9)",
          backdropFilter: "blur(12px)",
          borderBottom: "1px solid rgba(16, 185, 129, 0.2)",
          padding: "16px 24px",
          display: "flex",
          alignItems: "center",
          justifyContent: "space-between",
          flexWrap: "wrap",
          gap: 12,
        }}
      >
        <div style={{ display: "flex", alignItems: "center", gap: 12 }}>
          <div
            style={{
              width: 40,
              height: 40,
              borderRadius: "12px",
              background: "linear-gradient(135deg, #10b981, #059669)",
              display: "flex",
              alignItems: "center",
              justifyContent: "center",
            }}
          >
            <LayoutDashboard size={22} color="#fff" />
          </div>
          <h1 style={{ fontSize: "20px", fontWeight: 700, color: "#047857" }}>관리자 대시보드</h1>
        </div>
        <button
          onClick={onLogout}
          style={{
            display: "flex",
            alignItems: "center",
            gap: 8,
            padding: "10px 16px",
            border: "2px solid #a7f3d0",
            borderRadius: "10px",
            background: "#fff",
            color: "#047857",
            fontWeight: 600,
            cursor: "pointer",
          }}
        >
          <LogOut size={18} />
          로그아웃
        </button>
      </header>

      <main style={{ maxWidth: 1200, margin: "0 auto", padding: "24px" }}>
        <motion.div
          initial={{ opacity: 0, y: 20 }}
          animate={{ opacity: 1, y: 0 }}
          style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit, minmax(200px, 1fr))", gap: 16, marginBottom: 24 }}
        >
          {statsCards.map((card, i) => (
            <motion.div
              key={card.title}
              initial={{ opacity: 0, y: 20 }}
              animate={{ opacity: 1, y: 0 }}
              transition={{ delay: i * 0.05 }}
              style={{
                background: "#fff",
                borderRadius: "12px",
                padding: 20,
                border: "2px solid rgba(16, 185, 129, 0.2)",
                boxShadow: "0 4px 14px rgba(0,0,0,0.04)",
                display: "flex",
                alignItems: "center",
                justifyContent: "space-between",
              }}
            >
              <div>
                <p style={{ fontSize: "13px", color: "#6b7280", marginBottom: 4 }}>{card.title}</p>
                <p style={{ fontSize: "24px", fontWeight: 700, color: "#111" }}>{card.value}</p>
              </div>
              <div
                style={{
                  width: 44,
                  height: 44,
                  borderRadius: "12px",
                  background: card.color,
                  display: "flex",
                  alignItems: "center",
                  justifyContent: "center",
                }}
              >
                <card.icon size={22} color="#fff" />
              </div>
            </motion.div>
          ))}
        </motion.div>

        <div
          style={{
            background: "#fff",
            borderRadius: "16px",
            border: "2px solid rgba(16, 185, 129, 0.2)",
            boxShadow: "0 4px 20px rgba(0,0,0,0.06)",
            overflow: "hidden",
          }}
        >
          <div
            style={{
              padding: "20px 24px",
              display: "flex",
              flexWrap: "wrap",
              gap: 12,
              alignItems: "center",
              justifyContent: "space-between",
              borderBottom: "1px solid #e5e7eb",
            }}
          >
            <div style={{ display: "flex", gap: 8, flexWrap: "wrap" }}>
              {["admins", "users", "logs", "stats"].map((tab) => (
                <button
                  key={tab}
                  onClick={() => setActiveTab(tab)}
                  style={{
                    padding: "10px 16px",
                    borderRadius: "10px",
                    border: activeTab === tab ? "none" : "2px solid #d1fae5",
                    background: activeTab === tab ? "linear-gradient(135deg, #10b981, #059669)" : "#fff",
                    color: activeTab === tab ? "#fff" : "#047857",
                    fontWeight: 600,
                    cursor: "pointer",
                  }}
                >
                  {tab === "admins" && "관리자"}
                  {tab === "users" && "회원"}
                  {tab === "logs" && "접속 로그"}
                  {tab === "stats" && "일별 통계"}
                </button>
              ))}
            </div>
            <div style={{ position: "relative", flex: "1 1 200px", maxWidth: 280 }}>
              <Search
                size={18}
                style={{ position: "absolute", left: 12, top: "50%", transform: "translateY(-50%)", color: "#9ca3af" }}
              />
              <input
                type="text"
                placeholder="검색..."
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
                style={{
                  width: "100%",
                  height: 40,
                  padding: "0 12px 0 40px",
                  border: "2px solid #d1fae5",
                  borderRadius: "10px",
                  fontSize: "14px",
                  outline: "none",
                }}
              />
            </div>
          </div>

          <div style={{ padding: 24, overflowX: "auto" }}>
            {loading ? (
              <p style={{ textAlign: "center", color: "#6b7280", padding: 40 }}>데이터 로딩 중...</p>
            ) : (
              <AnimatePresence mode="wait">
                <motion.div
                  key={activeTab}
                  initial={{ opacity: 0, y: 10 }}
                  animate={{ opacity: 1, y: 0 }}
                  exit={{ opacity: 0 }}
                  transition={{ duration: 0.2 }}
                >
                  {activeTab === "admins" && (
                    <Table
                      cols={["관리자 ID", "이메일", "이름", "역할"]}
                      fieldMap={{ "관리자 ID": "adminId", "이메일": "adminEmail", "이름": "adminName", "역할": "role" }}
                      rows={filterList(admins, ["adminId", "adminEmail", "adminName", "role"])}
                    />
                  )}
                  {activeTab === "users" && (
                    <Table
                      cols={["이메일", "이름", "전화번호", "상태", "마지막 로그인"]}
                      fieldMap={{ "이메일": "email", "이름": "username", "전화번호": "phone", "상태": "status", "마지막 로그인": "lastLoginAt" }}
                      rows={filterList(users, ["email", "username", "phone", "status"])}
                    />
                  )}
                  {activeTab === "logs" && (
                    <Table
                      cols={["로그 ID", "회원 ID", "플랫폼", "IP", "접속일시"]}
                      fieldMap={{ "로그 ID": "accessLogId", "회원 ID": "userId", "플랫폼": "platform", "IP": "reqIp", "접속일시": "createdAt" }}
                      rows={filterList(logs, ["accessLogId", "userId", "platform", "reqIp"])}
                    />
                  )}
                  {activeTab === "stats" && (
                    <Table
                      cols={["날짜", "활성 회원", "전체 회원", "Android", "iOS", "Web"]}
                      fieldMap={{ "날짜": "statDate", "활성 회원": "activeUserCount", "전체 회원": "totalUserCount", "Android": "androidCount", "iOS": "iosCount", "Web": "webCount" }}
                      rows={filterList(stats, ["statDate"])}
                    />
                  )}
                </motion.div>
              </AnimatePresence>
            )}
          </div>
        </div>
      </main>
    </div>
  );
}

function Table({ cols, rows, fieldMap }) {
  const getField = (col) => (fieldMap && fieldMap[col]) || col;

  return (
    <table style={{ width: "100%", borderCollapse: "collapse", fontSize: "14px" }}>
      <thead>
        <tr style={{ borderBottom: "2px solid #e5e7eb" }}>
          {cols.map((c) => (
            <th
              key={c}
              style={{
                padding: "12px 16px",
                textAlign: "left",
                fontWeight: 600,
                color: "#374151",
              }}
            >
              {c}
            </th>
          ))}
        </tr>
      </thead>
      <tbody>
        {rows.length === 0 ? (
          <tr>
            <td colSpan={cols.length} style={{ padding: 40, textAlign: "center", color: "#6b7280" }}>
              데이터가 없습니다.
            </td>
          </tr>
        ) : (
          rows.map((row, i) => (
            <tr key={i} style={{ borderBottom: "1px solid #f3f4f6" }}>
              {cols.map((col) => {
                const key = getField(col);
                const val = row[key] ?? "-";
                return (
                  <td key={col} style={{ padding: "12px 16px", color: "#111" }}>
                    {typeof val === "object" && val !== null ? JSON.stringify(val) : String(val)}
                  </td>
                );
              })}
            </tr>
          ))
        )}
      </tbody>
    </table>
  );
}

function Admin() {
  const [isLoggedIn, setIsLoggedIn] = useState(() => !!localStorage.getItem("adminToken"));

  const handleLogin = () => setIsLoggedIn(true);
  const handleLogout = () => {
    localStorage.removeItem("adminToken");
    setIsLoggedIn(false);
  };

  return (
    <>
      {!isLoggedIn ? <LoginForm onLogin={handleLogin} /> : <Dashboard onLogout={handleLogout} />}
    </>
  );
}

export default Admin;
