import React, { useState, useEffect, useRef } from "react";
import { useSearchParams, useNavigate } from "react-router-dom";
import { Search, Sparkles } from "lucide-react";
import axios from "../axiosConfig";
import { getApiBaseUrl } from "../apiConfig";
import "bootstrap/dist/css/bootstrap.min.css";

function Dashboard() {
  const [searchParams, setSearchParams] = useSearchParams();
  const navigate = useNavigate();

  // 카카오 OAuth2 로그인 성공 후 리다이렉트 시 URL에 token이 있으면 저장하고 URL 정리
  useEffect(() => {
    const token = searchParams.get("token");
    const refreshToken = searchParams.get("refresh_token");
    if (token) {
      localStorage.setItem("token", token);
      if (refreshToken) localStorage.setItem("refresh_token", refreshToken);
      setSearchParams({}); // 쿼리 제거 (주소창에서 토큰 제거)
      window.dispatchEvent(new CustomEvent("token-stored"));
    }
  }, [searchParams, setSearchParams]);

  const [page, setPage] = useState(0);
  const [movies, setMovies] = useState([]);
  const [hasNext, setHasNext] = useState(false);
  const [imageTabStates, setImageTabStates] = useState({}); // 각 영화별 이미지 탭 상태
  const [contentType, setContentType] = useState("dvd"); // "dvd" 또는 "movie"
  const [listError, setListError] = useState(null); // 목록 로드 실패 시 메시지
  const [listLoading, setListLoading] = useState(false);
  const lastListRequestRef = useRef({ type: "dvd", page: 0 }); // 응답 경쟁 방지: 마지막 요청 타입/페이지만 반영
  const contentTopRef = useRef(null);

  // Netflix 스타일 카테고리 정의: { id, title, contentType, genre }
  const CATEGORIES = [
    { id: "popular-dvd", title: "🆕 최신 인기 DVD", contentType: "dvd", genre: null },
    { id: "popular-movie", title: "🆕 최신 인기 영화", contentType: "movie", genre: null },
    { id: "action-dvd", title: "액션 DVD", contentType: "dvd", genre: "Action" },
    { id: "comedy-dvd", title: "코미디 DVD", contentType: "dvd", genre: "Comedy" },
    { id: "drama-dvd", title: "드라마 DVD", contentType: "dvd", genre: "Drama" },
    { id: "romance-dvd", title: "로맨스 DVD", contentType: "dvd", genre: "Romance" },
    { id: "thriller-dvd", title: "스릴러 DVD", contentType: "dvd", genre: "Thriller" },
    { id: "horror-dvd", title: "공포 DVD", contentType: "dvd", genre: "Horror" },
    { id: "sci-fi-dvd", title: "SF DVD", contentType: "dvd", genre: "Science Fiction" },
    { id: "animation-dvd", title: "애니메이션 DVD", contentType: "dvd", genre: "Animation" },
    { id: "action-movie", title: "액션 영화", contentType: "movie", genre: "Action" },
    { id: "comedy-movie", title: "코미디 영화", contentType: "movie", genre: "Comedy" },
    { id: "drama-movie", title: "드라마 영화", contentType: "movie", genre: "Drama" },
    { id: "romance-movie", title: "로맨스 영화", contentType: "movie", genre: "Romance" },
    { id: "horror-movie", title: "공포 영화", contentType: "movie", genre: "Horror" },
    { id: "animation-movie", title: "애니메이션 영화", contentType: "movie", genre: "Animation" },
  ];

  const [searchKeyword, setSearchKeyword] = useState("");
  const [searchResults, setSearchResults] = useState([]);
  const [searchLoading, setSearchLoading] = useState(false);
  const [searchHasNext, setSearchHasNext] = useState(false);
  const [searchPage, setSearchPage] = useState(0);
  const [recommendedMovies, setRecommendedMovies] = useState([]);
  const [recommendedLoading, setRecommendedLoading] = useState(false);
  const [promptQuery, setPromptQuery] = useState("");
  const [promptResults, setPromptResults] = useState([]);
  const [promptLoading, setPromptLoading] = useState(false);
  const [promptResultsExpanded, setPromptResultsExpanded] = useState(false);
  const isLoggedIn = !!localStorage.getItem("token");

  const [categoriesData, setCategoriesData] = useState({});
  const [categoriesLoading, setCategoriesLoading] = useState(true);
  const [categoriesError, setCategoriesError] = useState(null);
  const [loadingMore, setLoadingMore] = useState({});
  const [contentTotals, setContentTotals] = useState(null); // { movieTotal, dvdTotal } from GET /api/v1/movie/totals

  const fetchCategoryPage = async (cat, pageNum) => {
    const base = getApiBaseUrl();
    const baseUrl = base ? base.replace(/\/$/, "") : "";
    const params = new URLSearchParams({ contentType: cat.contentType, page: String(pageNum) });
    if (cat.genre) params.set("genre", cat.genre);
    const url = `${baseUrl}/api/v1/movie/category/search?${params}`;
    const res = await fetch(url, { method: "POST", headers: { "Content-Type": "application/json" } });
    const json = await res.json();
    const movies = (json?.success && json?.data?.movies) ? json.data.movies : [];
    const hasNext = Boolean(json?.data?.hasNext);
    const totalCount = json?.data?.totalCount ?? null;
    return { movies, hasNext, totalCount };
  };

  // 대시보드 진입 시 카테고리별 목록 자동 로드 (Netflix 스타일) + 실패 시 재시도 지원
  const loadCategories = async () => {
    setCategoriesError(null);
    setCategoriesLoading(true);
    try {
      const results = await Promise.all(CATEGORIES.map(async (cat) => {
        const { movies, hasNext, totalCount } = await fetchCategoryPage(cat, 0);
        return { [cat.id]: { movies, hasNext, page: 0, totalCount } };
      }));
      const merged = results.reduce((acc, r) => ({ ...acc, ...r }), {});
      setCategoriesData(merged);
    } catch (err) {
      setCategoriesError("콘텐츠를 불러오지 못했습니다. 네트워크를 확인하고 다시 시도해 주세요.");
      setCategoriesData({});
    } finally {
      setCategoriesLoading(false);
    }
  };

  // 총 콘텐츠 수 전용 API (DB 기준, 배치 반영값)
  const loadContentTotals = async () => {
    const base = getApiBaseUrl();
    const baseUrl = base ? base.replace(/\/$/, "") : "";
    try {
      const res = await fetch(`${baseUrl}/api/v1/movie/totals`);
      const json = await res.json();
      if (json?.success && json?.data) {
        setContentTotals({
          movieTotal: json.data.movieTotal ?? 0,
          dvdTotal: json.data.dvdTotal ?? 0,
        });
      }
    } catch {
      setContentTotals(null);
    }
  };

  useEffect(() => {
    loadCategories();
    loadContentTotals();
  }, []);

  // 로그인 시 맞춤 추천 로드
  useEffect(() => {
    if (!isLoggedIn) return;
    const loadRecommended = async () => {
      setRecommendedLoading(true);
      try {
        const res = await axios.get("/api/v1/movie/recommend?contentType=dvd&limit=20");
        if (res.data?.success && Array.isArray(res.data?.data)) {
          setRecommendedMovies(res.data.data);
        }
      } catch (e) {
        setRecommendedMovies([]);
      } finally {
        setRecommendedLoading(false);
      }
    };
    loadRecommended();
  }, [isLoggedIn]);

  const fetchSearch = async (keyword, pageNum) => {
    if (!keyword || !keyword.trim()) return;
    const base = getApiBaseUrl();
    const baseUrl = base ? base.replace(/\/$/, "") : "";
    const res = await fetch(`${baseUrl}/api/v1/movie/keyword/search?q=${encodeURIComponent(keyword.trim())}&page=${pageNum}`, {
      method: "POST",
      headers: { "Content-Type": "application/json" },
    });
    const json = await res.json();
    const movies = (json?.success && json?.data?.movies) ? json.data.movies : [];
    const hasNext = Boolean(json?.data?.hasNext);
    return { movies, hasNext };
  };

  const handleSearch = async () => {
    if (!searchKeyword.trim()) return;
    setSearchLoading(true);
    const { movies, hasNext } = await fetchSearch(searchKeyword, 0);
    setSearchResults(movies);
    setSearchHasNext(hasNext);
    setSearchPage(0);
    setSearchLoading(false);
  };

  // AI 프롬프트 추천 (로그인 없이 호출 가능)
  const fetchPromptRecommend = async () => {
    const q = (promptQuery || "").trim();
    if (!q) return;
    setPromptLoading(true);
    setPromptResults([]);
    setPromptResultsExpanded(false);
    try {
      const base = getApiBaseUrl();
      const baseUrl = base ? base.replace(/\/$/, "") : "";
      const params = new URLSearchParams({ q, contentType: "movie" });
      const url = `${baseUrl}/api/v1/movie/recommend/prompt?${params}`;
      const res = await fetch(url, { method: "GET", headers: { "Content-Type": "application/json" } });
      const json = await res.json();
      const list = (json?.success && Array.isArray(json?.data)) ? json.data : [];
      setPromptResults(list);
    } catch (e) {
      setPromptResults([]);
    } finally {
      setPromptLoading(false);
    }
  };

  const loadMoreCategory = async (cat) => {
    const current = categoriesData[cat.id];
    if (!current?.hasNext || loadingMore[cat.id]) return;
    setLoadingMore((prev) => ({ ...prev, [cat.id]: true }));
    const nextPage = (current.page || 0) + 1;
    try {
      const { movies: newMovies, hasNext } = await fetchCategoryPage(cat, nextPage);
      setCategoriesData((prev) => ({
        ...prev,
        [cat.id]: {
          movies: [...(prev[cat.id]?.movies || []), ...newMovies],
          hasNext,
          page: nextPage,
          totalCount: prev[cat.id]?.totalCount,
        },
      }));
    } finally {
      setLoadingMore((prev) => ({ ...prev, [cat.id]: false }));
    }
  };

  // DVD 목록 (Popular DVD Select) - 기존 API 호환
  const loadDvdList = async (pageNum) => {
    const requestId = { type: "dvd", page: pageNum };
    lastListRequestRef.current = requestId;
    setListError(null);
    setListLoading(true);
    const base = getApiBaseUrl();
    const url = base ? `${base.replace(/\/$/, "")}/api/v1/movie/search?page=${pageNum}` : `/api/v1/movie/search?page=${pageNum}`;
    try {
      const res = await fetch(url, { method: "POST", headers: { "Content-Type": "application/json" } });
      const json = await res.json();
      if (lastListRequestRef.current !== requestId) return;
      if (!res.ok) {
        setMovies([]);
        setHasNext(false);
        setListError(`DVD 목록을 불러올 수 없습니다. (${res.status})`);
        return;
      }
      const data = json?.data;
      if (json?.success && data && Array.isArray(data.movies)) {
        setContentType("dvd");
        setMovies(data.movies);
        setHasNext(Boolean(data.hasNext));
        setPage(pageNum);
      } else {
        setMovies([]);
        setHasNext(false);
      }
    } catch (err) {
      if (lastListRequestRef.current !== requestId) return;
      setMovies([]);
      setHasNext(false);
      setListError("DVD 목록을 불러올 수 없습니다. 잠시 후 다시 시도해 주세요.");
    } finally {
      if (lastListRequestRef.current === requestId) setListLoading(false);
    }
  };

  // 영화 목록 (Popular MOVIE Select)
  const loadMovieList = async (pageNum) => {
    const requestId = { type: "movie", page: pageNum };
    lastListRequestRef.current = requestId;
    setListError(null);
    setListLoading(true);
    const base = getApiBaseUrl();
    const url = base ? `${base.replace(/\/$/, "")}/api/v1/movie/playing/search?page=${pageNum}` : `/api/v1/movie/playing/search?page=${pageNum}`;
    try {
      const res = await fetch(url, { method: "POST", headers: { "Content-Type": "application/json" } });
      const json = await res.json();
      if (lastListRequestRef.current !== requestId) return;
      if (!res.ok) {
        setMovies([]);
        setHasNext(false);
        setListError(`영화 목록을 불러올 수 없습니다. (${res.status})`);
        return;
      }
      const data = json?.data;
      if (json?.success && data && Array.isArray(data.movies)) {
        setContentType("movie");
        setMovies(data.movies);
        setHasNext(Boolean(data.hasNext));
        setPage(pageNum);
      } else {
        setMovies([]);
        setHasNext(false);
      }
    } catch (err) {
      if (lastListRequestRef.current !== requestId) return;
      setMovies([]);
      setHasNext(false);
      setListError("영화 목록을 불러올 수 없습니다. 잠시 후 다시 시도해 주세요.");
    } finally {
      if (lastListRequestRef.current === requestId) setListLoading(false);
    }
  };

  const getMovies = loadDvdList;
  const getPlayingMovies = loadMovieList;

  const scrollToContentTop = () => {
    if (contentTopRef.current) {
      contentTopRef.current.scrollIntoView({ behavior: "smooth", block: "start" });
      return;
    }
    window.scrollTo({ top: 0, behavior: "smooth" });
  };

  const getYouTubeUrl = (movie) => {
    if (!movie) return "";
    if (movie.trailerUrl && String(movie.trailerUrl).trim() !== "") {
      return movie.trailerUrl;
    }
    const query = `${movie.movieName || ""} 예고편`;
    return `https://www.youtube.com/results?search_query=${encodeURIComponent(query)}`;
  };

  const handlePrevPage = () => {
    if (page > 0) {
      const prevPage = page - 1;
      setPage(prevPage);
      scrollToContentTop();
      if (contentType === "dvd") {
        getMovies(prevPage);
      } else {
        getPlayingMovies(prevPage);
      }
    }
  };

  const handleNextPage = () => {
    if (hasNext) {
      const nextPage = page + 1;
      setPage(nextPage);
      scrollToContentTop();
      if (contentType === "dvd") {
        getMovies(nextPage);
      } else {
        getPlayingMovies(nextPage);
      }
    }
  };

  // 이미지 탭 전환
  const toggleImageTab = (movieName, tab) => {
    setImageTabStates((prev) => ({
      ...prev,
      [movieName]: tab,
    }));
  };

  // 현재 활성화된 이미지 탭 가져오기
  const getActiveTab = (movieName) => {
    return imageTabStates[movieName] || "poster";
  };

  // 깨진 한글을 감지하는 함수 (CJK 한자가 포함되어 있으면 깨진 것으로 판단)
  const isCorruptedKorean = (text) => {
    if (!text) return false;
    // CJK Unified Ideographs 범위 (U+4E00 ~ U+9FFF)
    // 정상적인 한글 설명에는 중국 한자가 없어야 함
    const cjkPattern = /[\u4E00-\u9FFF]/;
    return cjkPattern.test(text);
  };

  // 설명 텍스트를 표시하는 함수
  const getDisplayOverview = (overview, ct = contentType) => {
    const noDescMessage = ct === "movie" 
      ? "이 영화, 말이 없네요 🤐" 
      : "이 DVD, 말이 없네요 🤐";
    
    // overview가 없거나 비어있는 경우
    if (!overview || overview.trim() === "") {
      return noDescMessage;
    }
    if (overview === "No description available.") {
      return noDescMessage;
    }
    if (isCorruptedKorean(overview)) {
      return noDescMessage;
    }
    return overview;
  };
  const formatGenreForDisplay = (value) => {
    const raw = String(value ?? "").trim();
    if (!raw) return "";
    // 짧은 장르 문자열은 한 줄 유지, 길어질 때만 쉼표 기준 줄바꿈
    if (raw.length <= 28) return raw;
    return raw
      .split(",")
      .map((item) => item.trim())
      .filter(Boolean)
      .join(",\n");
  };

  // Netflix 스타일 한 줄 메타: "2024 · 2시간 15분 · 15세 관람가"
  const getOneLineMeta = (movie) => {
    const parts = [];
    const year = (movie.releaseDate || movie.releasedAt || "").slice(0, 4);
    if (year) parts.push(year);
    if (movie.runtime) parts.push(`${movie.runtime}분`);
    if (movie.certification) parts.push(movie.certification);
    return parts.join(" · ");
  };

  // 1년 이내 개봉/발매 여부 (최신 배지용)
  const isRecentRelease = (movie) => {
    const dateStr = movie.releaseDate || movie.releasedAt || "";
    const year = parseInt(dateStr.slice(0, 4), 10);
    const now = new Date().getFullYear();
    return !isNaN(year) && year >= now - 1;
  };

  // 평점 참여 인원 포맷 (1.2만 명)
  const formatVoteCount = (n) => {
    if (!n || n <= 0) return null;
    if (n >= 10000) return `${(n / 10000).toFixed(1)}만 명`;
    if (n >= 1000) return `${(n / 1000).toFixed(1)}천 명`;
    return `${n.toLocaleString()}명`;
  };

  const palette = {
    bg: "var(--ds-bg)",
    panel: "var(--ds-panel)",
    panelSoft: "var(--ds-panel-soft)",
    border: "var(--ds-border)",
    text: "var(--ds-text)",
    textMuted: "var(--ds-text-muted)",
    primary: "var(--ds-primary)",
    primarySoft: "var(--ds-primary-soft)",
    secondary: "var(--ds-secondary)",
    secondarySoft: "var(--ds-secondary-soft)",
  };
  const detailFontFamily =
    "-apple-system, BlinkMacSystemFont, 'SF Pro Display', 'Segoe UI', system-ui, sans-serif";

  const getSelectButtonStyle = (type) => {
    const active = contentType === type;
    const isMovie = type === "movie";
    const color = isMovie ? palette.secondary : palette.primary;
    const soft = isMovie ? palette.secondarySoft : palette.primarySoft;
    return {
      border: `1px solid ${active ? color : palette.border}`,
      background: active ? soft : "rgba(255,255,255,0.02)",
      color: palette.text,
      padding: "10px 16px",
      borderRadius: "12px",
      cursor: "pointer",
      fontSize: "14px",
      fontWeight: 700,
      letterSpacing: "0.2px",
      minWidth: "160px",
      transition: "all 0.2s ease",
      boxShadow: active ? `0 8px 24px ${soft}` : "none",
    };
  };

  const getPageButtonStyle = (enabled) => ({
    background: enabled ? "rgba(255,255,255,0.06)" : "rgba(255,255,255,0.02)",
    color: enabled ? palette.text : "#6b7280",
    border: `1px solid ${enabled ? palette.border : "rgba(255,255,255,0.04)"}`,
    padding: "8px 14px",
    borderRadius: "10px",
    cursor: enabled ? "pointer" : "not-allowed",
    fontSize: "13px",
    fontWeight: 600,
  });

  return (
    <div
      className="dashboard-page"
      style={{
        width: "100%",
        background:
          "radial-gradient(1200px 600px at 20% -10%, rgba(236, 72, 153, 0.08), transparent), radial-gradient(1000px 500px at 100% -20%, rgba(139, 92, 246, 0.08), transparent), linear-gradient(135deg, #0f172a 0%, #1e1b4b 50%, #0f172a 100%)",
        minHeight: "100vh",
        padding: "20px 12px 28px",
        fontFamily: detailFontFamily,
        maxWidth: "100vw",
        overflowX: "hidden",
      }}
    >
      <div ref={contentTopRef} style={{ width: "100%", padding: "0 5px" }}>
        {/* 검색 바 - Magic 스타일 */}
        <div
          style={{
            marginBottom: "24px",
            position: "relative",
            display: "flex",
            alignItems: "stretch",
            borderRadius: "14px",
            overflow: "hidden",
            boxShadow: "0 8px 32px rgba(0,0,0,0.35), 0 0 0 1px rgba(255,255,255,0.06)",
            background: "rgba(255,255,255,0.04)",
            backdropFilter: "blur(12px)",
          }}
        >
          <div style={{ display: "flex", alignItems: "center", paddingLeft: "14px", color: "rgba(255,255,255,0.5)" }}>
            <Search size={20} strokeWidth={2} />
          </div>
          <input
            type="text"
            placeholder="제목·장르 검색"
            value={searchKeyword}
            onChange={(e) => setSearchKeyword(e.target.value)}
            onKeyDown={(e) => e.key === "Enter" && handleSearch()}
            style={{
              flex: 1,
              minWidth: 0,
              padding: "14px 12px 14px 8px",
              border: "none",
              background: "transparent",
              color: "#fff",
              fontSize: "15px",
              outline: "none",
            }}
          />
          <button
            type="button"
            onClick={handleSearch}
            disabled={searchLoading}
            style={{
              margin: "6px",
              padding: "10px 20px",
              background: searchKeyword.trim()
                ? "linear-gradient(135deg, #ec4899 0%, #8b5cf6 100%)"
                : "rgba(255,255,255,0.08)",
              color: searchKeyword.trim() ? "#fff" : "rgba(255,255,255,0.4)",
              border: "none",
              borderRadius: "10px",
              fontWeight: 700,
              fontSize: "14px",
              cursor: searchLoading ? "wait" : "pointer",
              boxShadow: searchKeyword.trim() ? "0 4px 16px rgba(236, 72, 153, 0.4)" : "none",
              transition: "all 0.25s ease",
              display: "flex",
              alignItems: "center",
              gap: "6px",
            }}
            onMouseEnter={(e) => {
              if (!searchLoading && searchKeyword.trim()) {
                e.currentTarget.style.transform = "scale(1.02)";
                e.currentTarget.style.boxShadow = "0 6px 20px rgba(236, 72, 153, 0.5)";
              }
            }}
            onMouseLeave={(e) => {
              e.currentTarget.style.transform = "scale(1)";
              e.currentTarget.style.boxShadow = searchKeyword.trim() ? "0 4px 16px rgba(236, 72, 153, 0.4)" : "none";
            }}
          >
            <Search size={16} />
            {searchLoading ? "검색 중" : "검색"}
          </button>
        </div>

        {/* 검색 결과 */}
        {searchKeyword.trim() && (
          <div style={{ marginBottom: "24px" }}>
            <h3 style={{ color: palette.text, fontSize: "18px", fontWeight: 700, marginBottom: "12px", textAlign: "center" }}>
              검색 결과
            </h3>
            {searchResults.length > 0 ? (
              <div className="dashboard-scroll-row" style={{ display: "flex", gap: "12px", overflowX: "auto", paddingBottom: "8px", flexWrap: "nowrap" }}>
                {searchResults.map((item, idx) => {
                  const ct = item.contentType || "dvd";
                  const cat = { id: "search", contentType: ct };
                  return (
                    <div
                      key={`search-${item.movieName}-${idx}`}
                      style={{
                        flex: "0 0 auto",
                        width: "140px",
                        minWidth: "140px",
                        borderRadius: "10px",
                        overflow: "hidden",
                        boxShadow: "0 4px 12px rgba(0,0,0,0.3)",
                        background: palette.panel,
                      }}
                    >
                      <button
                        type="button"
                        style={{ width: "100%", margin: 0, padding: 0, border: "none", background: "none", cursor: "pointer", display: "block" }}
                        onClick={() => navigate("/dashboard/images", { state: { movie: { ...item, contentType: ct } } })}
                      >
                        {item.posterPath ? (
                          <img src={`https://image.tmdb.org/t/p/w342${item.posterPath}`} alt={item.movieName} draggable={false} style={{ width: "100%", height: "200px", objectFit: "cover", display: "block" }} />
                        ) : (
                          <img src="/no-poster-placeholder.png" alt="No Image" style={{ width: "100%", height: "200px", objectFit: "cover", display: "block" }} />
                        )}
                      </button>
                      <button
                        type="button"
                        style={{ width: "100%", padding: "8px", border: "none", background: "transparent", color: palette.text, fontSize: "13px", fontWeight: 600, textAlign: "center", whiteSpace: "nowrap", overflow: "hidden", textOverflow: "ellipsis", cursor: "pointer" }}
                        onClick={() => navigate("/dashboard/images", { state: { movie: { ...item, contentType: ct } } })}
                      >
                        {item.movieName}
                      </button>
                    </div>
                  );
                })}
                <div style={{ flex: "1 1 0", minWidth: "20px", flexShrink: 0 }} aria-hidden="true" />
              </div>
            ) : !searchLoading && (
              <div style={{ color: palette.textMuted, padding: "20px", textAlign: "center" }}>검색 결과가 없습니다.</div>
            )}
          </div>
        )}

        {categoriesLoading && (
          <div className="mb-3 p-3 rounded text-center" style={{ color: palette.text, background: "rgba(255,255,255,0.03)", border: `1px solid ${palette.border}` }}>
            콘텐츠를 불러오고 있어요...
          </div>
        )}
        {categoriesError && !categoriesLoading && (
          <div className="mb-3 p-4 rounded text-center" style={{ color: palette.text, background: "rgba(255,255,255,0.03)", border: `1px solid ${palette.border}` }}>
            <p style={{ marginBottom: "12px", color: palette.textMuted }}>{categoriesError}</p>
            <button
              type="button"
              onClick={loadCategories}
              className="btn btn-primary"
              style={{ padding: "8px 20px", borderRadius: "8px", fontWeight: 600 }}
            >
              다시 시도
            </button>
          </div>
        )}

        {/* AI 프롬프트 추천 - Magic 스타일 카드 + 멋진 버튼 */}
        <div
          style={{
            marginBottom: "24px",
            borderRadius: "16px",
            overflow: "hidden",
            boxShadow: "0 12px 40px rgba(0,0,0,0.4), 0 0 0 1px rgba(255,215,0,0.12)",
            background: "linear-gradient(145deg, rgba(30,27,75,0.6) 0%, rgba(15,23,42,0.8) 100%)",
            backdropFilter: "blur(12px)",
          }}
        >
          <div style={{ padding: "16px 18px 12px" }}>
            <div style={{ display: "flex", alignItems: "center", gap: "8px", marginBottom: "10px" }}>
              <div style={{ color: "#fbbf24", display: "flex", alignItems: "center" }}>
                <Sparkles size={20} strokeWidth={2} />
              </div>
              <h3 style={{ color: palette.text, fontSize: "17px", fontWeight: 700, margin: 0, textAlign: "center" }}>
                AI로 추천받기
              </h3>
            </div>
            <p style={{ color: palette.textMuted, fontSize: "12px", marginBottom: "12px", lineHeight: 1.4 }}>
              보고 싶은 영화를 한 줄로 적어 보세요. (예: 비 오는 날 보기 좋은 감성 영화, 연인과 볼 로맨스)
            </p>
            <div
              style={{
                display: "flex",
                alignItems: "center",
                borderRadius: "12px",
                overflow: "hidden",
                border: "1px solid rgba(255,215,0,0.2)",
                background: "rgba(0,0,0,0.25)",
                boxShadow: "inset 0 1px 2px rgba(0,0,0,0.2)",
              }}
            >
              <input
                type="text"
                value={promptQuery}
                onChange={(e) => setPromptQuery(e.target.value)}
                onKeyDown={(e) => e.key === "Enter" && fetchPromptRecommend()}
                placeholder="원하는 영화를 설명해 주세요"
                maxLength={200}
                style={{
                  flex: 1,
                  minWidth: 0,
                  padding: "12px 8px",
                  border: "none",
                  background: "transparent",
                  color: palette.text,
                  fontSize: "14px",
                  outline: "none",
                }}
              />
              <button
                type="button"
                onClick={fetchPromptRecommend}
                disabled={promptLoading || !promptQuery.trim()}
                style={{
                  padding: "10px 14px",
                  border: "none",
                  background: "transparent",
                  cursor: promptLoading || !promptQuery.trim() ? "not-allowed" : "pointer",
                  display: "flex",
                  alignItems: "center",
                  gap: "6px",
                  transition: "opacity 0.2s ease",
                  color: promptQuery.trim() && !promptLoading
                    ? "#fbbf24"
                    : "rgba(255,255,255,0.3)",
                  fontSize: "18px",
                  fontWeight: 700,
                  letterSpacing: "2px",
                  flexShrink: 0,
                  opacity: promptLoading ? 0.6 : 1,
                }}
              >
                {promptLoading ? (
                  <Sparkles size={16} />
                ) : (
                  "···"
                )}
              </button>
            </div>
          </div>
          {promptLoading && (
            <div style={{ color: palette.textMuted, padding: "16px", textAlign: "center", fontSize: "14px" }}>AI가 영화를 고르는 중...</div>
          )}
          {!promptLoading && promptResults.length > 0 && (() => {
            const showMore = promptResults.length > 10 && !promptResultsExpanded;
            const listToShow = showMore ? promptResults.slice(0, 10) : promptResults;
            const restCount = promptResults.length - 10;
            return (
              <div className="dashboard-scroll-row" style={{ display: "flex", gap: "12px", overflowX: "auto", paddingBottom: "8px", WebkitOverflowScrolling: "touch", flexWrap: "nowrap" }}>
                {listToShow.map((item, idx) => {
                  const m = item.movie || item;
                  const reason = item.reason || "";
                  const ct = m.contentType || "movie";
                  return (
                    <div
                      key={`prompt-${m.movieName}-${idx}`}
                      style={{
                        flex: "0 0 auto",
                        width: "160px",
                        minWidth: "160px",
                        borderRadius: "10px",
                        overflow: "hidden",
                        boxShadow: "0 4px 12px rgba(0,0,0,0.3)",
                        background: palette.panel,
                        border: "1px solid rgba(255, 215, 0, 0.25)",
                      }}
                    >
                      <button
                        type="button"
                        style={{ width: "100%", margin: 0, padding: 0, border: "none", background: "none", cursor: "pointer", display: "block" }}
                        onClick={() => navigate("/dashboard/images", { state: { movie: { ...m, contentType: ct } } })}
                      >
                        {m.posterPath ? (
                          <img src={`https://image.tmdb.org/t/p/w342${m.posterPath}`} alt={m.movieName} draggable={false} style={{ width: "100%", height: "200px", objectFit: "cover", display: "block" }} />
                        ) : (
                          <img src="/no-poster-placeholder.png" alt="No Image" style={{ width: "100%", height: "200px", objectFit: "cover", display: "block" }} />
                        )}
                      </button>
                      <div style={{ padding: "8px" }}>
                        <button
                          type="button"
                          style={{ width: "100%", padding: 0, border: "none", background: "transparent", color: palette.text, fontSize: "13px", fontWeight: 600, textAlign: "center", whiteSpace: "nowrap", overflow: "hidden", textOverflow: "ellipsis", cursor: "pointer" }}
                          onClick={() => navigate("/dashboard/images", { state: { movie: { ...m, contentType: ct } } })}
                        >
                          {m.movieName}
                        </button>
                        {reason && (
                          <p style={{ margin: "4px 0 0", color: palette.textMuted, fontSize: "11px", lineHeight: 1.3, display: "-webkit-box", WebkitLineClamp: 2, WebkitBoxOrient: "vertical", overflow: "hidden" }}>
                            {reason}
                          </p>
                        )}
                      </div>
                    </div>
                  );
                })}
                {showMore && (
                  <button
                    type="button"
                    onClick={() => setPromptResultsExpanded(true)}
                    style={{
                      flex: "0 0 auto",
                      width: "160px",
                      minWidth: "160px",
                      height: "236px",
                      margin: 0,
                      padding: 0,
                      border: "2px dashed rgba(251, 191, 36, 0.4)",
                      background: "linear-gradient(135deg, rgba(251, 191, 36, 0.06), rgba(245, 158, 11, 0.06))",
                      borderRadius: "14px",
                      cursor: "pointer",
                      display: "flex",
                      flexDirection: "column",
                      alignItems: "center",
                      justifyContent: "center",
                      color: "rgba(251, 191, 36, 0.95)",
                      fontSize: "14px",
                      fontWeight: 700,
                      transition: "all 0.2s ease",
                      gap: "6px",
                    }}
                  >
                    <span>더 보기 →</span>
                    <span style={{ fontSize: "13px", color: "rgba(251, 191, 36, 0.85)", fontWeight: 600 }}>
                      {listToShow.length} / {promptResults.length}
                    </span>
                  </button>
                )}
                <div style={{ flex: "1 1 0", minWidth: "20px", flexShrink: 0 }} aria-hidden="true" />
              </div>
            );
          })()}
          {!promptLoading && promptResults.length === 0 && promptQuery.trim() && (
            <div style={{ color: palette.textMuted, padding: "12px", textAlign: "center", fontSize: "13px" }}>추천 결과가 없거나 서버를 확인해 주세요.</div>
          )}
        </div>

        {/* 맞춤 추천 (로그인 시) */}
        {isLoggedIn && (
          <div style={{ marginBottom: "24px" }}>
            <h3 style={{ color: palette.text, fontSize: "18px", fontWeight: 700, marginBottom: "12px", textAlign: "center" }}>
              ✨ 당신을 위한 맞춤 추천
            </h3>
            {recommendedLoading ? (
              <div style={{ color: palette.textMuted, padding: "20px", textAlign: "center" }}>추천 목록 불러오는 중...</div>
            ) : recommendedMovies.length > 0 ? (
              <div className="dashboard-scroll-row" style={{ display: "flex", gap: "12px", overflowX: "auto", paddingBottom: "8px", WebkitOverflowScrolling: "touch", flexWrap: "nowrap" }}>
                {recommendedMovies.map((item, idx) => {
                  const ct = item.contentType || "dvd";
                  return (
                    <div
                      key={`recommend-${item.movieName}-${idx}`}
                      style={{
                        flex: "0 0 auto",
                        width: "140px",
                        minWidth: "140px",
                        borderRadius: "10px",
                        overflow: "hidden",
                        boxShadow: "0 4px 12px rgba(0,0,0,0.3)",
                        background: palette.panel,
                        border: "1px solid rgba(255, 215, 0, 0.3)",
                      }}
                    >
                      <button
                        type="button"
                        style={{ width: "100%", margin: 0, padding: 0, border: "none", background: "none", cursor: "pointer", display: "block" }}
                        onClick={() => navigate("/dashboard/images", { state: { movie: { ...item, contentType: ct } } })}
                      >
                        {item.posterPath ? (
                          <img src={`https://image.tmdb.org/t/p/w342${item.posterPath}`} alt={item.movieName} draggable={false} style={{ width: "100%", height: "200px", objectFit: "cover", display: "block" }} />
                        ) : (
                          <img src="/no-poster-placeholder.png" alt="No Image" style={{ width: "100%", height: "200px", objectFit: "cover", display: "block" }} />
                        )}
                      </button>
                      <button
                        type="button"
                        style={{ width: "100%", padding: "8px", border: "none", background: "transparent", color: palette.text, fontSize: "13px", fontWeight: 600, textAlign: "center", whiteSpace: "nowrap", overflow: "hidden", textOverflow: "ellipsis", cursor: "pointer" }}
                        onClick={() => navigate("/dashboard/images", { state: { movie: { ...item, contentType: ct } } })}
                      >
                        {item.movieName}
                      </button>
                    </div>
                  );
                })}
                <div style={{ flex: "1 1 0", minWidth: "20px", flexShrink: 0 }} aria-hidden="true" />
              </div>
            ) : (
              <div style={{ color: palette.textMuted, padding: "20px", textAlign: "center", fontSize: "14px" }}>좋아요를 누르면 취향에 맞는 작품을 추천해 드려요!</div>
            )}
          </div>
        )}

        {/* Netflix 스타일 카테고리별 가로 스크롤 행 */}
        {!categoriesLoading && CATEGORIES.map((cat) => {
          const catData = categoriesData[cat.id];
          const catMovies = catData?.movies || [];
          const hasNext = catData?.hasNext ?? false;
          const isLoadingMore = loadingMore[cat.id];
          const totalCount = catData?.totalCount;
          const currentCount = catMovies.length;
          if (catMovies.length === 0) return null;
          return (
            <div key={cat.id} style={{ marginBottom: "24px" }}>
              <h3 style={{ color: palette.text, fontSize: "18px", fontWeight: 700, marginBottom: "12px", textAlign: "center" }}>
                {cat.title}
              </h3>
              <div
                className="dashboard-scroll-row"
                style={{
                  display: "flex",
                  gap: "12px",
                  overflowX: "auto",
                  overflowY: "hidden",
                  paddingBottom: "8px",
                  scrollbarWidth: "thin",
                  WebkitOverflowScrolling: "touch",
                }}
              >
                {catMovies.map((item, index) => {
                  const activeTab = getActiveTab(item.movieName);
                  const currentImagePath = activeTab === "poster" ? item.posterPath : item.backdropPath;
                  const goToDetail = () => {
                    navigate("/dashboard/images", { state: { movie: { ...item, contentType: cat.contentType } } });
                  };
                  return (
                    <div
                      key={`${cat.id}-${item.movieName}-${index}`}
                      style={{
                        flex: "0 0 auto",
                        width: "140px",
                        minWidth: "140px",
                        borderRadius: "10px",
                        overflow: "hidden",
                        boxShadow: "0 4px 12px rgba(0,0,0,0.3)",
                        background: palette.panel,
                      }}
                    >
                      <button
                        type="button"
                        className="js-fast-tap"
                        style={{
                          width: "100%",
                          margin: 0,
                          padding: 0,
                          border: "none",
                          background: "none",
                          cursor: "pointer",
                          display: "block",
                        }}
                        onClick={goToDetail}
                      >
                        {currentImagePath ? (
                          <img
                            src={`https://image.tmdb.org/t/p/w342${currentImagePath}`}
                            alt={item.movieName}
                            draggable={false}
                            style={{ width: "100%", height: "200px", objectFit: "cover", display: "block" }}
                          />
                        ) : (
                          <img src="/no-poster-placeholder.png" alt="No Image" style={{ width: "100%", height: "200px", objectFit: "cover", display: "block" }} />
                        )}
                      </button>
                      <button
                        type="button"
                        className="js-fast-tap"
                        style={{
                          width: "100%",
                          padding: "8px",
                          border: "none",
                          background: "transparent",
                          color: palette.text,
                          fontSize: "13px",
                          fontWeight: 600,
                          textAlign: "center",
                          whiteSpace: "nowrap",
                          overflow: "hidden",
                          textOverflow: "ellipsis",
                          cursor: "pointer",
                        }}
                        onClick={goToDetail}
                      >
                        {item.movieName}
                      </button>
                    </div>
                  );
                })}
                {hasNext && (
                  <button
                    type="button"
                    onClick={() => loadMoreCategory(cat)}
                    disabled={isLoadingMore}
                    style={{
                      flex: "0 0 auto",
                      width: "140px",
                      minWidth: "140px",
                      height: "236px",
                      margin: 0,
                      padding: 0,
                      border: "2px dashed rgba(139, 92, 246, 0.3)",
                      background: "linear-gradient(135deg, rgba(236, 72, 153, 0.05), rgba(139, 92, 246, 0.05))",
                      borderRadius: "14px",
                      cursor: isLoadingMore ? "wait" : "pointer",
                      display: "flex",
                      flexDirection: "column",
                      alignItems: "center",
                      justifyContent: "center",
                      color: "rgba(167, 139, 250, 1)",
                      fontSize: "14px",
                      fontWeight: 700,
                      transition: "all 0.2s ease",
                      gap: "8px",
                    }}
                  >
                    {isLoadingMore ? (
                      <>
                        <span className="spinner-border spinner-border-sm mb-2" style={{ color: palette.primary }} />
                        로딩 중...
                      </>
                    ) : (
                      <>
                        <span>더 보기 →</span>
                        {totalCount && (
                          <span style={{ fontSize: "13px", color: "rgba(236, 72, 153, 0.9)", fontWeight: 600 }}>
                            {currentCount} / {totalCount}
                          </span>
                        )}
                      </>
                    )}
                  </button>
                )}
                {/* 100% 화면비율에서 오른쪽 여백을 채우는 spacer */}
                <div style={{ flex: "1 1 0", minWidth: "20px", flexShrink: 0 }} aria-hidden="true" />
              </div>
            </div>
          );
        })}

        {/* 총 편수: GET /api/v1/movie/totals (DB 기준, 배치 반영) */}
        {(() => {
          const movieTotal = contentTotals?.movieTotal ?? null;
          const dvdTotal = contentTotals?.dvdTotal ?? null;
          const sum = [movieTotal, dvdTotal].filter((n) => n != null).reduce((a, b) => a + b, 0);
          const hasCounts = movieTotal != null && dvdTotal != null;
          return hasCounts ? (
            <div
              style={{
                marginTop: "32px",
                marginBottom: "16px",
                padding: "14px 18px",
                borderRadius: "12px",
                background: "rgba(255,255,255,0.04)",
                border: "1px solid rgba(255,255,255,0.08)",
                textAlign: "center",
                color: palette.textMuted,
                fontSize: "14px",
              }}
            >
              <span style={{ color: palette.text, fontWeight: 600 }}>총 콘텐츠</span>
              {" · "}
              영화 {movieTotal}편 · DVD {dvdTotal}편
              <span style={{ marginLeft: "6px", fontSize: "12px", opacity: 0.85 }}>(중복 제외, 합계 {sum}편)</span>
              <div style={{ marginTop: "8px", fontSize: "12px", color: "#e53935" }}>
                매일 새벽 2시에 DVD, 새벽 3시에 영화가 최신정보로 업데이트됩니다
              </div>
            </div>
          ) : null;
        })()}

        {/* Footer - 비 오는 거리 배경 이미지 (mukkai 푸터와 동일 높이 320px) */}
        <footer
          style={{
            position: "relative",
            width: "100%",
            minHeight: "320px",
            marginTop: "48px",
            overflow: "hidden",
            backgroundImage: "url('/images/footer-bg.png')",
            backgroundSize: "cover",
            backgroundPosition: "center 35%",
            backgroundRepeat: "no-repeat",
            borderRadius: "16px",
            display: "flex",
            alignItems: "flex-start",
          }}
        >
          <div style={{ position: "relative", zIndex: 2, width: "100%", padding: "32px 24px", textAlign: "center" }}>
            <div style={{ marginBottom: "24px" }}>
              <h3 style={{ fontSize: "clamp(24px, 5vw, 30px)", fontWeight: 700, margin: 0, marginBottom: "8px", background: "linear-gradient(90deg, #fbbf24, #f97316, #ef4444)", WebkitBackgroundClip: "text", WebkitTextFillColor: "transparent", backgroundClip: "text" }}>Designed by 홀릭</h3>
              <p style={{ color: "#d1d5db", fontSize: "18px", fontWeight: 500, margin: 0 }}>박준호 26년 봄</p>
            </div>
            <div style={{ marginTop: "32px", paddingTop: "24px" }}>
              <p style={{ color: "#6b7280", fontSize: "12px", margin: 0 }}>© 2025 DVDHolic. All rights reserved.</p>
            </div>
          </div>
        </footer>
      </div>


    </div>
  );
}

export default Dashboard;
